// ---- misc UI constants ----
constexpr int SWIPE_SCROLL_STEP  = 90;

// ---- Global status bar (lv_layer_sys → drawn above everything) ----
// Always-visible 240×22 strip across the top of the display. Left zone is
// dynamic (MESHCOMOD on Home tab, mail-icon + total-unread count on the
// other tabs). Right zone is a fixed stack: connection icon (WiFi or
// BLE, whichever is up), clock, battery percent, battery icon. The bar
// sits on lv_layer_sys so modals on lv_layer_top can't cover it, and the
// tabview / chat overlay are explicitly sized to leave the top 22 px
// clear.
// Runtime (not constexpr) so the UI-scale can grow it to fit bigger status-bar text — set to SC(22)
// once at boot in begin(), before the UI is built. Stays 22 on the non-scaled boards.
static lv_coord_t STATUSBAR_H = 22;
// True while the Reader/Web page is collapsed and showing its URL in the status bar's
// title zone — updateGlobalStatusBar then hides the clock to make room for the URL.
static bool s_reader_bar_url = false;
// True whenever the Reader/Web page is open — suppresses the tall status-bar glass
// fade so the address reads on a solid bar (no gradient behind it).
static bool s_reader_page_open = false;
struct GlobalStatusBar {
  lv_obj_t* root;
  lv_obj_t* left_label;
  lv_obj_t* conn_icon;       // Wi-Fi glyph
  lv_obj_t* ble_icon;        // Bluetooth glyph (separate from Wi-Fi)
  lv_obj_t* sleep_icon;      // idle light-sleep readiness indicator (T-Deck only)
  lv_obj_t* sd_icon;         // microSD read/write activity LED (left of Wi-Fi)
  lv_obj_t* async_icon;      // async mesh-request spinner glyph (centre, transient)
  lv_obj_t* clock;
  lv_obj_t* batt_pct;
  lv_obj_t* batt_icon;
  lv_obj_t* layout_label;   // EN / BG indicator, right side
  lv_obj_t* chan_gear;      // channel-settings gear, left of the thread name (channels only)
  lv_obj_t* sig_bars[4];    // mesh signal-strength bars (lit count = last-heard SNR)
  lv_obj_t* sig_box;        // container holding sig_bars (slides over when charging hides the %)
  lv_obj_t* inbox_add;      // chat/channel-overview actions, shown in the lower row of the
  lv_obj_t* inbox_mark;     // DOUBLE-height bar (only on the overview): [+ add | ✓ read | QR]
  lv_obj_t* inbox_qr;
  lv_obj_t* chat_back;      // "‹" affordance shown while in a chat (tap the bar = close)
  lv_obj_t* fade;           // glass backdrop for the lower row in a chat/overview: top-row solid,
                            //   fading to translucent at the bottom so the chat shows through it
  lv_obj_t* dim;            // full-bar scrim shown while a modal popup is up, so the bar dims with
                            //   the rest of the screen (the popup's own backdrop starts below it)
};
static GlobalStatusBar g_statusbar = {};
static void updateGlobalStatusBar();   // fwd decl, called from refresh tick

// Settings detail pages render the global status bar at DOUBLE height: the bar's
// back chevron + page title then read like a tall title bar (the whole bar still
// taps to go Back — see statusBarTapCb), and the extra room is free for future
// per-page header content. updateGlobalStatusBar enlarges the back label while tall.
static bool s_statusbar_tall = false;
// Generic "app page" hook so full-screen tool pages (RF Monitor, Spectrum) get the SAME
// tall status-bar + back-chevron treatment as settings detail pages — NOT a second header
// bar. When s_apppage_title is set, updateGlobalStatusBar goes tall and paints "‹ <title>"
// centred in the bar; a tap on the bar calls s_apppage_close (see statusBarTapCb).
static const char* s_apppage_title = nullptr;
static void      (*s_apppage_close)() = nullptr;
static inline lv_coord_t statusBarCurH() { return s_statusbar_tall ? (lv_coord_t)(STATUSBAR_H * 2) : STATUSBAR_H; }
static void statusBarSetTall(bool tall) {
  s_statusbar_tall = tall;
  if (g_statusbar.root) lv_obj_set_height(g_statusbar.root, statusBarCurH());
  // (updateGlobalStatusBar drives this every tick + refreshes the left zone; it must
  // NOT be called from here — it calls back into statusBarSetTall = recursion.)
}
static const char* tsBlockReason();    // fwd decl (defined near idle-sleep hooks)
static const char* tsWakeReasonStr(touchSleep::WakeReason r);  // fwd decl (defined near idle-sleep hooks)
static void batteryTapCb(lv_event_t* e);   // fwd decl (defined near the battery chart) — Settings "Battery" button reuses it

// microSD read/write activity. markSdIo() stamps the time of the last SD access
// (SD-backed tile cache, SD tile packs, file manager, mount). UITask::loop lights
// a small LED in the status bar for a short window after each access. Cost on the
// hot path is one 32-bit timestamp store; the loop toggle is edge-triggered so it
// only touches LVGL when the lit/dark state actually flips. Written from both
// cores (core-0 fetch task + core-1 UI) — an aligned word store is atomic on the
// S3, and a stale read only ever mistimes the LED by a frame, which is harmless.
static volatile uint32_t g_sd_io_ms = 0;
static inline void markSdIo() { const uint32_t t = millis(); g_sd_io_ms = t ? t : 1; }

// Async mesh-request activity: a small spinner glyph in the status bar while a
// request is sending or awaiting a reply. markMeshRequest() stamps a send; the
// indicator also stays lit while a UI reply is pending (s_ui_ping_deadline_ms,
// telemetry/ping) or the sightline worker is busy (s_los_busy).
static volatile uint32_t g_mesh_req_ms = 0;
static inline void markMeshRequest() { const uint32_t t = millis(); g_mesh_req_ms = t ? t : 1; }
// How long the LED stays lit after the last SD access (ms). Long enough that a
// single quick read is visible, short enough to read as "activity" not "on".
static constexpr uint32_t k_sd_io_led_ms = 180;

// Active chat thread name, surfaced in the status bar's left zone. The in-chat
// header bar (back button + name) was removed to give the conversation the full
// height — like the Terminal/Files views, the chat name lives in the status bar
// and a small floating HOME button handles exit. Empty = no chat open.
static char s_chat_title[40] = {0};
static void setChatStatusTitle(const char* sanitized) {   // already glyph-sanitized name, or nullptr to clear
  if (sanitized && sanitized[0]) {
    strncpy(s_chat_title, sanitized, sizeof(s_chat_title) - 1);
    s_chat_title[sizeof(s_chat_title) - 1] = '\0';
  } else {
    s_chat_title[0] = '\0';
  }
  updateGlobalStatusBar();
}
/** Bottom tab indices. Left→right: Chats(0), Contacts(1), Home(2), Map(3)[, Sensors][, Settings]. */
// Bottom-bar order, left→right: Chats, Contacts, Home (middle), Map[, Sensors], Settings.
// On Heltec V4 (HAS_EXPANSION_KIT) a 6th "Sensors" tab is inserted before Settings,
// shifting Settings from index 4 → 5; other touch boards keep the 5-tab layout.
constexpr int CHAT_INBOX_TAB_INDEX   = 0;
constexpr int CONTACTS_TAB_INDEX     = 1;
constexpr int HOME_TAB_INDEX         = 2;
constexpr int MAP_TAB_INDEX          = 3;
#if defined(HAS_EXPANSION_KIT)
// Runtime (not constexpr): the Sensors tab is only inserted when an environment
// sensor is present AND the user pref is on (see sensorsUiWanted()), so its
// index — and Settings' index after it — are decided in buildUiTree. Defaults
// here are the "no Sensors tab" layout (Settings at 4); buildUiTree promotes
// them to 4/5 when the Sensors tab is added. SENSORS_TAB_INDEX = -1 means
// "absent", so every `== SENSORS_TAB_INDEX` refresh check simply never matches.
// These are only ever read as plain ints (comparisons / nav args), so mutable
// is fine; CHAT/CONTACTS/HOME/MAP stay constexpr.
static int SENSORS_TAB_INDEX  = -1;
static int SETTINGS_TAB_INDEX = 4;
static int TAB_LAST           = 4;
#else
constexpr int SETTINGS_TAB_INDEX     = 4;
constexpr int TAB_LAST               = 4;
#endif

// Objects flagged thus are clickable but must NOT be a keyboard-nav focus target —
// navCollect skips them. Used for the full-area map touch/pan catcher, which would
// otherwise get focused and painted solid by the focus highlight (white over the map).
#define NAV_SKIP_FLAG LV_OBJ_FLAG_USER_1

// A "horizontal-only" secondary keyboard-nav target (e.g. the per-row settings gear in the chat
// list): UP/DOWN skip it so vertical nav walks the primary rows, RIGHT/LEFT reach it, and — the
// key part — it does NOT suppress its parent row from being harvested. Without this, navCollect's
// leaf rule (a clickable with a clickable child is treated as a container) picks the gear over the
// row, leaving the row un-focusable so keyboard users could only open thread-settings, never the chat.
#define NAV_HMOVE_FLAG LV_OBJ_FLAG_USER_2

// An object whose keyboard-nav focus highlight should be an ACCENT-coloured
// tint (matching its own touch-press feedback) instead of navFocusCb's
// default white reverse-video fill. Used by app-drawer tiles (addAppTile):
// a solid white block over a small rounded icon chip reads as a glitch, not
// a highlight — while on the pager (no touch, so this IS the only feedback
// a user ever sees on these tiles) it needs to look intentional. Reuses the
// exact same COLOR_ACCENT tint the tile's own LV_STATE_PRESSED style already
// defines, so a keyboard/encoder-focused tile matches what a touch/trackball
// press already looks like on every board.
#define NAV_ACCENTFOCUS_FLAG LV_OBJ_FLAG_USER_3

// ---- Chat overlay layout ----
constexpr int CHAT_HDR_H       = 0;    // in-chat header bar removed; thread name shows in the status bar
#if CAP_LARGE_SCREEN
constexpr int CHAT_COMP_H      = 64;   // big screen: ~2× the typing box (60px) + chrome
#else
constexpr int CHAT_COMP_H      = 34;   // composer row, single line (slimmed 50 → 40 → 34; hugs the 30px textbox)
#endif
constexpr int CHAT_COMP_MAX_LINES = 4; // composer grows up to this many wrapped lines, then scrolls vertically
// Current composer-row height. The composer wraps long text to multiple lines
// and grows UPWARD (its bottom stays pinned, the message list above shrinks)
// instead of horizontally scrolling a single line. The chat layout helpers
// below derive the message-area height + composer Y from this, so a taller
// composer automatically reclaims space from the message list. Reset to
// CHAT_COMP_H on each chat-panel (re)build; updated by chatComposerAutoGrow().
static lv_coord_t s_comp_h = CHAT_COMP_H;
constexpr int CHAT_KB_H        = 130;  // on-screen keyboard (portrait)
// Bottom tab-bar height (matches lv_tabview_create in buildUiTree). A tab
// page's usable content area is the screen minus the status bar and tab bar —
// queried live so it tracks the current rotation (240×260 portrait /
// 320×180 landscape).
#if CAP_LARGE_SCREEN
constexpr int TABBAR_H = 46;   // taller on the big 800×480 panel — room for the coloured F-key shapes
#else
constexpr int TABBAR_H = 30;   // bottom nav bar (trimmed from 38; icons stay g_font_16)
#endif
static inline lv_coord_t tabContentW() { return lv_disp_get_hor_res(nullptr); }
static inline lv_coord_t tabContentH() { return lv_disp_get_ver_res(nullptr) - STATUSBAR_H - TABBAR_H; }
// Usable area for a centered modal below the global status bar (small margin).
// Popups were sized for the 320-tall portrait screen; these let them shrink to
// fit the 240-tall landscape one. Backdrops should use the full screen so the
// dark overlay covers everything and the card centers on-screen.
static inline lv_coord_t modalAvailW() { return lv_disp_get_hor_res(nullptr) - 12; }
static inline lv_coord_t modalAvailH() { return lv_disp_get_ver_res(nullptr) - STATUSBAR_H - 12; }
// Chat-detail geometry — runtime so the conversation view fills the screen and
// tracks rotation. The keyboard is half the screen tall in landscape (matches
// kbApplyLayoutForRotation), full CHAT_KB_H in portrait.
static inline bool       chatLandscape() { return lv_disp_get_hor_res(nullptr) > lv_disp_get_ver_res(nullptr); }
static inline lv_coord_t chatScreenW()   { return lv_disp_get_hor_res(nullptr); }
// The status bar is DOUBLE height in a chat (thread name on the lower row + a centred
// cog). chatBarH() is that full visual height (used by the channel/blocked sheets). The
// conversation itself, though, starts just under the SOLID top row (STATUSBAR_H): the
// bar's lower row is a translucent glass strip (see updateGlobalStatusBar) that the
// bubbles scroll UNDER — p.msgs carries a top inset == that row so the newest content
// still rests below the bar.
static inline lv_coord_t chatBarH()      { return (lv_coord_t)(STATUSBAR_H * 2); }
static inline lv_coord_t chatScreenH()   { return lv_disp_get_ver_res(nullptr) - STATUSBAR_H; }
static inline lv_coord_t chatKbH()       { return chatLandscape() ? (lv_disp_get_ver_res(nullptr) / 2) : CHAT_KB_H; }
// The message list spans the FULL height under the header down to the screen bottom
// (or the keyboard top) — the composer FLOATS over its lower edge with a transparent
// row, and p.msgs carries a bottom inset == s_comp_h so the newest bubble rests just
// above the composer while older bubbles scroll UNDER it. (s_comp_h tracks the
// composer's current, possibly grown, height; chatComposerAutoGrow keeps the inset.)
static inline lv_coord_t chatMsgHOpen()  { return chatScreenH() - CHAT_HDR_H; }
static inline lv_coord_t chatCompYOpen() { return chatScreenH() - s_comp_h; }
// with keyboard shown:
static inline lv_coord_t chatMsgHKb()    { return chatScreenH() - CHAT_HDR_H - chatKbH(); }
static inline lv_coord_t chatCompYKb()   { return chatScreenH() - s_comp_h - chatKbH(); }

