// ---- Discovered adverts ring buffer ----
// Filled by UITask::discoveredContact() each time an advert comes in for a
// node that's not in contacts[]. Browsable + addable via the Discovered
// modal opened from the Contacts tab "Found" button.
constexpr int DISCOVERED_MAX = 48;   // ring of recently-heard nodes not in contacts; persisted in chunks
struct LvDiscoveredEntry {
  bool used;
  bool in_contacts;
  uint8_t path_len;
  uint32_t last_advert_ts;
  uint32_t recv_ms;
  ContactInfo ci;
};
// PSRAM-first allocator (falls back to internal RAM) for moving large static UI buffers off
// the scarce internal SRAM. Safe as a static initializer: PSRAM is up before C++ ctors run,
// and the fallback keeps the original internal behaviour if PSRAM is ever unavailable.
static void* psAlloc(size_t n) {
    void* p = heap_caps_malloc(n, MALLOC_CAP_SPIRAM);
    if (!p) p = heap_caps_malloc(n, MALLOC_CAP_8BIT);
    // Zero-init: these buffers replace zero-initialized static UI arrays, and
    // their callers rely on that — e.g. s_discovered[].used is the validity flag
    // for the "Found" list. Without this, fresh-boot PSRAM garbage makes random
    // entries look "used" and the Found list shows corrupt contacts.
    if (p) memset(p, 0, n);
    return p;
}
static LvDiscoveredEntry* s_discovered = (LvDiscoveredEntry*)psAlloc(sizeof(LvDiscoveredEntry) * DISCOVERED_MAX);
static uint32_t s_discovered_seq = 0;

// Count of discovered adverts NOT yet in contacts (the "Discovered" badge).
static int discoveredCount() {
  int n = 0;
  for (int i = 0; i < DISCOVERED_MAX; ++i)
    if (s_discovered && s_discovered[i].used && !s_discovered[i].in_contacts) ++n;
  return n;
}
// Drop every discovered entry (the Purge action on the Discovered list).
static void purgeDiscovered() {
  if (!s_discovered) return;
  for (int i = 0; i < DISCOVERED_MAX; ++i) s_discovered[i].used = false;
}

// ---- Persist the discovered ring across reboots (NVS blob "disc") ----
static const char*   KDISC = "disc";   // chunk 0 (older firmware wrote ≤24 records here)
static bool          s_disc_dirty   = false;
static unsigned long s_disc_save_at = 0;
// Compact on-disk record (84 B/entry). SdNvsPrefs's SD .kv backend (used under
// Launcher) silently DROPS any single value > 2048 B on load (sdLoad bails on
// the oversize record), so we cap each stored blob at DISC_PER_CHUNK records
// (2 + 24*84 = 2018 B) and split the ring across as many chunk keys ("disc",
// "disc1", …) as DISCOVERED_MAX needs. We persist only what the Discovered list
// redraws — the bulky parts of ContactInfo (out_path[64], shared_secret, …) are
// re-derived live.
static const uint8_t   DISC_BLOB_VER  = 1;
static constexpr size_t DISC_REC_SZ    = PUB_KEY_SIZE + 32 + 4 + 16;   // pubkey + name + 4×u8 + 4×u32
static constexpr int    DISC_PER_CHUNK = 24;                           // 2 + 24*84 = 2018 B < 2048 cap
static constexpr int    DISC_CHUNKS    = (DISCOVERED_MAX + DISC_PER_CHUNK - 1) / DISC_PER_CHUNK;
static constexpr size_t DISC_BLOB_SZ = 2 + DISC_PER_CHUNK * DISC_REC_SZ;
static uint8_t* s_disc_blob = nullptr;   // Discovered-ring persistence scratch — lazy PSRAM (internal fallback): ~2 KB off internal DRAM
static uint8_t* discBlob() {             // alloc on first save/load; returns null only on (unlikely) OOM
  if (!s_disc_blob) { s_disc_blob = (uint8_t*)heap_caps_malloc(DISC_BLOB_SZ, MALLOC_CAP_SPIRAM);
                      if (!s_disc_blob) s_disc_blob = (uint8_t*)heap_caps_malloc(DISC_BLOB_SZ, MALLOC_CAP_8BIT); }
  return s_disc_blob;
}
static inline void     discPutU32(uint8_t*& p, uint32_t v) { p[0]=(uint8_t)v; p[1]=(uint8_t)(v>>8); p[2]=(uint8_t)(v>>16); p[3]=(uint8_t)(v>>24); p+=4; }
static inline uint32_t discGetU32(const uint8_t*& p) { uint32_t v=(uint32_t)p[0]|((uint32_t)p[1]<<8)|((uint32_t)p[2]<<16)|((uint32_t)p[3]<<24); p+=4; return v; }
static void discChunkKey(int chunk, char* out, size_t cap) {
  if (chunk == 0) { strncpy(out, KDISC, cap - 1); out[cap - 1] = '\0'; }
  else            { snprintf(out, cap, "disc%d", chunk); }
}
static void saveDiscovered() {
  if (!s_discovered || !discBlob()) return;
  int src = 0;   // walk the ring once, emitting used entries into successive chunk blobs
  for (int chunk = 0; chunk < DISC_CHUNKS; ++chunk) {
    uint8_t* p = s_disc_blob;
    *p++ = DISC_BLOB_VER;
    uint8_t* pcount = p++;            // back-patched with the entry count
    uint8_t count = 0;
    while (src < DISCOVERED_MAX && count < DISC_PER_CHUNK) {
      const LvDiscoveredEntry& e = s_discovered[src++];
      if (!e.used) continue;
      memcpy(p, e.ci.id.pub_key, PUB_KEY_SIZE); p += PUB_KEY_SIZE;
      memcpy(p, e.ci.name, 32); p += 32;
      *p++ = e.ci.type;
      *p++ = e.ci.flags;
      *p++ = e.path_len;
      *p++ = e.in_contacts ? 1 : 0;
      discPutU32(p, e.last_advert_ts);
      discPutU32(p, e.recv_ms);
      discPutU32(p, (uint32_t)e.ci.gps_lat);
      discPutU32(p, (uint32_t)e.ci.gps_lon);
      ++count;
    }
    *pcount = count;
    char key[8]; discChunkKey(chunk, key, sizeof key);
    if (count > 0) touchPrefsSetBlob(key, s_disc_blob, (size_t)(p - s_disc_blob));
    else           touchPrefsSetBlob(key, nullptr, 0);   // clear an empty trailing chunk
  }
  s_disc_dirty = false;
}
static void loadDiscovered() {
  if (!s_discovered || !discBlob()) return;
  memset(s_discovered, 0, sizeof(LvDiscoveredEntry) * DISCOVERED_MAX);
  int dst = 0;
  for (int chunk = 0; chunk < DISC_CHUNKS && dst < DISCOVERED_MAX; ++chunk) {
    char key[8]; discChunkKey(chunk, key, sizeof key);
    size_t got = touchPrefsGetBlob(key, s_disc_blob, DISC_BLOB_SZ);
    if (got < 2 || s_disc_blob[0] != DISC_BLOB_VER) continue;   // missing / garbage chunk -> skip
    uint8_t count = s_disc_blob[1];
    const uint8_t* p   = s_disc_blob + 2;
    const uint8_t* end = s_disc_blob + got;
    for (uint8_t i = 0; i < count && dst < DISCOVERED_MAX && (size_t)(end - p) >= DISC_REC_SZ; ++i) {
      LvDiscoveredEntry& e = s_discovered[dst++];
      e.used = true;
      memcpy(e.ci.id.pub_key, p, PUB_KEY_SIZE); p += PUB_KEY_SIZE;
      memcpy(e.ci.name, p, 32); p += 32; e.ci.name[31] = '\0';
      e.ci.type         = *p++;
      e.ci.flags        = *p++;
      e.path_len        = *p++;
      e.ci.out_path_len = e.path_len;
      e.in_contacts     = (*p++ != 0);
      e.last_advert_ts  = discGetU32(p);
      e.ci.last_advert_timestamp = e.last_advert_ts;
      e.recv_ms         = discGetU32(p);
      e.ci.gps_lat      = (int32_t)discGetU32(p);
      e.ci.gps_lon      = (int32_t)discGetU32(p);
      e.ci.shared_secret_valid = false;   // force secret recompute on first use
    }
  }
}
// Coalesce a burst of adverts into one write ~20 s later (flash-churn guard).
static void markDiscoveredDirty() { s_disc_dirty = true; s_disc_save_at = millis() + 20000; }
static void discoveredFlushIfDue(unsigned long now) {
  if (s_disc_dirty && (long)(now - s_disc_save_at) >= 0) saveDiscovered();
}
// Synchronous flush for the deliberate reboot / power-off / download-mode paths
// (mirrors the chat-history flush) so a manual reboot never drops recent finds.
static void discoveredFlushNow() { if (s_disc_dirty) saveDiscovered(); }
// Remove discovered entries heard via more hops than the configured limit (the
// "auto-delete above N hops" setting; 0 = off). Returns true if anything went.
static bool discoveredSweepHops() {
  if (!s_discovered) return false;
#if defined(ESP32)
  const uint8_t maxhops = touchPrefsGetDiscoveredMaxHops();
  if (maxhops == 0) return false;
  bool changed = false;
  for (int i = 0; i < DISCOVERED_MAX; ++i)
    if (s_discovered[i].used && s_discovered[i].path_len > maxhops) {
      s_discovered[i].used = false;
      changed = true;
    }
  if (changed) markDiscoveredDirty();
  return changed;
#else
  return false;
#endif
}

// ---- Touch-init deferred flag ----
static bool g_cap_touch_hw_started = false;

// ---- LVGL draw buffer ----
// 240x24 RGB565 = 11,520 bytes. Allocated in PSRAM at UITask::begin() so the
// internal DRAM stays free for WiFi DMA buffers (esp_wifi_init needs ~50 KB
// of DRAM; with the buffer + LVGL widgets in DRAM the device was OOM'ing as
// soon as WiFi came up). PSRAM is slower than DRAM but the Adafruit ST7789
// SPI driver reads the buffer linearly which the cache handles well.
//
// 1.5x the original 240x16 size — modest bump to reduce setAddrWindow
// round-trips without giving LVGL more headroom to over-invalidate.
// Double-buffering and 240x40 were tried and starved the CHSC6X poll cadence
// (touch I2C is read from inside lv_timer_handler at LV_INDEV_DEF_READ_PERIOD
// = 30 ms, and bigger render windows pushed effective poll rate to ~11 Hz).
// 48 lines × 240 × 2 B = 23 KB. Lives in internal DMA-capable DRAM (see
// allocator below) which reads ~3× faster than PSRAM during SPI push.
// Doubled from 24 to amortize the per-flush setAddrWindow + startWrite/
// endWrite overhead. Tried double-buffering (two 23 KB internal blocks)
// — bootlooped after the top bar showed, because the second 23 KB block
// starved Bluedroid's DMA-DRAM pool at init time. Stayed single-buffer.
// Was 48 — dropped to 24 to claw back ~12 KB of internal DMA-DRAM for
// the Wi-Fi tile-fetch task stack (which has to live in internal RAM
// because mbedTLS/lwIP crash on PSRAM stacks under this Arduino-ESP32
// build). 24 × 240 × 2 B = 11.5 KB. Flush time is bound by SPI clock
// (80 MHz), not memcpy speed, so the throughput delta is small —
// LVGL just calls flush_cb more often.
static constexpr int LV_DRAW_BUF_LINES = 24;
static lv_color_t* g_draw_buffer = nullptr;
static uint32_t    g_draw_buf_px  = 240 * LV_DRAW_BUF_LINES;   // actual buffer size in px; shrinks if the full alloc fails at boot
#if CAP_LARGE_SCREEN
// UI resolution scaling (Tanmatsu, no touchscreen). LVGL renders at s_lv_pw x s_lv_ph (PHYSICAL
// portrait) and lvglFlush upscales each already-rotated band to the 480x800 panel. s_lv_pw == the
// panel width (480) means 100% / native (no upscale). Set once at boot from touchPrefsGetUiScale().
static constexpr int    TAN_PANEL_PW   = 480, TAN_PANEL_PH = 800;   // physical panel (portrait)
static constexpr size_t TAN_SCALE_BUF_PX = 86400;                   // one upscaled band (<= 19200 px * 4) — PSRAM
static int       s_lv_pw = TAN_PANEL_PW, s_lv_ph = TAN_PANEL_PH;    // LVGL physical resolution
static uint16_t* s_scale_buf = nullptr;                             // upscale scratch (lazy PSRAM)
#endif

// ---- Global UI state instance ----
LvUiState g_lv = {};

/** If `cp` has no glyph in `font`, show '*' instead of LVGL's missing-glyph box. Preserves \\n \\r \\t. */
static bool uiFontHasGlyph(const lv_font_t* font, uint32_t cp) {
  if (!font) return true;
  if (cp == '\n' || cp == '\r' || cp == '\t') return true;
  if (cp < 0x20u) return true;
  lv_font_glyph_dsc_t dsc{};
  return lv_font_get_glyph_dsc(font, &dsc, cp, 0);
}

/**
 * Copy UTF-8 `in` → `out` (NUL-terminated, capped). Codepoints not in `font` become ASCII '*'.
 * Invalid UTF-8 bytes become '*'.
 */
static void copyUtf8ReplacingMissingGlyphs(const lv_font_t* font, char* out, size_t out_cap, const char* in) {
  if (!out || out_cap == 0) return;
  out[0] = '\0';
  if (!in) return;
  size_t      w   = 0;
  const char* p   = in;
  const char* end = in + strlen(in);

  while (*p && w + 1 < out_cap) {
    const char*     seq_beg = p;
    uint32_t        cp      = 0;
    bool             ok      = false;

    const unsigned char c0 = static_cast<unsigned char>(*p);
    if (c0 < 0x80u) {
      cp = c0;
      p += 1;
      ok = true;
    } else if ((c0 & 0xE0u) == 0xC0u && end - p >= 2) {
      const unsigned char c1 = static_cast<unsigned char>(p[1]);
      if ((c1 & 0xC0u) == 0x80u) {
        cp = (static_cast<uint32_t>(c0 & 0x1Fu) << 6) | (c1 & 0x3Fu);
        if (cp >= 0x80u) {
          p += 2;
          ok = true;
        }
      }
    } else if ((c0 & 0xF0u) == 0xE0u && end - p >= 3) {
      const unsigned char c1 = static_cast<unsigned char>(p[1]);
      const unsigned char c2 = static_cast<unsigned char>(p[2]);
      if ((c1 & 0xC0u) == 0x80u && (c2 & 0xC0u) == 0x80u) {
        cp = (static_cast<uint32_t>(c0 & 0x0Fu) << 12) |
             (static_cast<uint32_t>(c1 & 0x3Fu) << 6) | (c2 & 0x3Fu);
        if (cp >= 0x800u && !(cp >= 0xD800u && cp <= 0xDFFFu)) {
          p += 3;
          ok = true;
        }
      }
    } else if ((c0 & 0xF8u) == 0xF0u && end - p >= 4) {
      const unsigned char c1 = static_cast<unsigned char>(p[1]);
      const unsigned char c2 = static_cast<unsigned char>(p[2]);
      const unsigned char c3 = static_cast<unsigned char>(p[3]);
      if ((c1 & 0xC0u) == 0x80u && (c2 & 0xC0u) == 0x80u && (c3 & 0xC0u) == 0x80u) {
        cp = (static_cast<uint32_t>(c0 & 0x07u) << 18) |
             (static_cast<uint32_t>(c1 & 0x3Fu) << 12) |
             (static_cast<uint32_t>(c2 & 0x3Fu) << 6) | (c3 & 0x3Fu);
        if (cp >= 0x10000u && cp <= 0x10FFFFu) {
          p += 4;
          ok = true;
        }
      }
    }

    if (!ok) {
      out[w++] = '*';
      p = seq_beg + 1;
      continue;
    }

    if (uiFontHasGlyph(font, cp)) {
      for (const char* q = seq_beg; q < p && w + 1 < out_cap; ++q) out[w++] = *q;
    } else {
      out[w++] = '*';
    }
  }
  out[w] = '\0';
}

