static int16_t  s_home_env_hist_temp_t10[kHomeEnvHistoryPoints] = {};
static int16_t  s_home_env_hist_hum[kHomeEnvHistoryPoints] = {};
static int16_t  s_home_env_hist_press_hpa10[kHomeEnvHistoryPoints] = {};
