static bool      s_update_available = false;
static bool      s_verchk_ran       = false;     // a check has completed (ok or failed)
static volatile bool s_verchk_request  = false;  // UI -> core-0 worker: please check
static volatile bool s_verchk_done     = false;  // worker -> UI: result ready
static bool          s_verchk_recheck  = false;  // force a fresh check now (e.g. update channel changed)

// microSD size/free for the About page. usedBytes() scans the FAT (slow, and contends
// with the worker's own SD writes) — doing it on the UI thread froze the About sheet and
// dropped the Back tap. Off-load it to the core-0 worker; sysInfoText reads these.
static volatile bool s_sdinfo_request  = false;  // UI -> worker: rescan SD usage
// UI -> worker: write the chat-history snapshot to storage. The full-file write
// can stall for multiple seconds in SPIFFS garbage collection on SD-less boards
// (Heltec V4); on the loop thread that froze the whole UI, incl. touch wake
// (the "ui:hist 6140ms" field stall). The loop thread snapshots the ring, the
// worker writes the snapshot; shutdown/reboot still write synchronously.
static volatile bool s_hist_flush_req  = false;  // snapshot armed, waiting for the worker
static volatile bool s_hist_flush_busy = false;  // worker owns the snapshot + the history file
static volatile bool s_hist_flush_ok   = true;   // last worker write result (retry on false)
static bool uiHistWorkerFlush();                 // defined with the storage code below
static volatile bool s_sdinfo_done     = false;  // worker -> UI: a result exists
static volatile bool s_sdinfo_ok       = false;  // card present + sizes valid
static uint64_t      s_sdinfo_tot      = 0;
static uint64_t      s_sdinfo_free     = 0;
static volatile int  s_verchk_latest_n = -1;     // highest published pre-alpha_N (-1 = failed)
#if defined(ESP32) && defined(MULTI_TRANSPORT_COMPANION) && CAP_OTA
// Wi-Fi OTA self-update — native dual-OTA boards only (V4 + standalone T-Deck). The button is
// gated on touchHasOtaUpdateSlot() (a spare A/B slot exists), so Launcher single-slot installs and
// the Tanmatsu (AppFS) never reach this — they update out-of-band. Arduino Update.begin() does the
// slot select + the image-fits-the-slot check, so a too-small legacy slot fails cleanly.
static volatile bool s_ota_request = false;      // UI -> worker: download + flash the latest bin
static volatile int  s_ota_state   = 0;          // 0 idle, 1 running, 2 success, 3 error
static volatile int  s_ota_pct     = 0;          // download/write progress 0..100
static volatile int  s_ota_target_n = -1;        // beta_N the worker should fetch (latest, or a chosen older one)
static char          s_ota_msg[80] = {0};        // error detail surfaced to the UI
static bool          touchHasOtaUpdateSlot();    // fwd: spare-A/B-slot probe, defined further below
#endif

