// "Blocked users" entry — opens the ignore-list manager.
static void channelLongSheetBlockedCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED) return;
  closeChannelLongSheet();
  openBlockedUsersModal();
}

// "Log in again" (room threads) — blank re-login to the room server. Passwordless
// works for a client the room already knows (LOGIN_OK with stored permissions,
// replay-guard-free; a flooded one also refreshes the server's path to us). The
// LOGIN_OK re-arms our keep-alive, whose first REQ clears the server's
// push-abandon counter — resuming a room that went one-way-dead (issue #89:
// "no possibility to log in once it is done"). A REBOOTED server forgets
// non-admin clients; that case needs the passworded Join from Contacts.
static void threadSheetRoomLoginCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  const int idx = s_channel_long_idx;
  closeChannelLongSheet();
  uint8_t pub[32];
  if (g_lv.task->getThreadContactPub(idx, pub) && the_mesh.uiRoomRelogin(pub) != MSG_SEND_FAILED)
    g_lv.task->showAlert(TR("Logging in again..."), 1400);
  else
    g_lv.task->showAlert(TR("Couldn't send login"), 1400);
}

// "Reset path" (DM sheet) — wipes the cached return path for this chat's contact so
// the next send re-floods, without the detour through the Contacts tab (wyvern.red
// feedback; same action as the contact sheet's Reset path).
// "Delete history" (chat/channel settings sheet): tombstone every message of the
// thread after a confirm. The thread row itself stays (the channel stays joined,
// the contact stays) — this only wipes the conversation content.
static int s_hist_clear_thread = -1;
static void histClearApply() {
  if (!g_lv.task || s_hist_clear_thread < 0) return;
  const int idx = s_hist_clear_thread;
  s_hist_clear_thread = -1;
  const int cleared = g_lv.task->clearThreadHistory(idx);
  refreshThreadLists();                                    // cleared history vanishes instantly
  if (g_lv.dm.detail_open) refreshChatDetailAsync(g_lv.dm);
  if (g_lv.ch.detail_open) refreshChatDetailAsync(g_lv.ch);
  // Persist synchronously so the cleared chat stays cleared across an immediate hard
  // reset; the compact write keeps it fast enough not to hitch the UI.
  if (cleared) g_lv.task->persistHistoryNow();
  char msg[40];
  snprintf(msg, sizeof msg, TR("Deleted %d messages"), cleared);
  g_lv.task->showAlert(msg, 1400);
}
static void threadSheetClearHistCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  const int idx = s_channel_long_idx;
  closeChannelLongSheet();
  s_hist_clear_thread = idx;
  showConfirm(TR("Delete this chat's entire history?\nThe chat itself stays."),
              TR("Delete"), histClearApply);
}

static void threadSheetResetPathCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  const int idx = s_channel_long_idx;
  closeChannelLongSheet();
  uint8_t pub[32];
  if (g_lv.task->getThreadContactPub(idx, pub) && the_mesh.uiResetContactPath(pub)) {
    g_lv.task->showAlert(TR("Path reset"), 1000);
    refreshContactsList();
  } else {
    g_lv.task->showAlert(TR("Path reset failed"), 1200);
  }
}

// Chat-icon chooser (channels): tap picks an emoji for the chat-list avatar via the
// emoji sheet in pick mode; long-press resets to the automatic two-letter avatar.
static void openEmojiPickerPick(void (*cb)(const char* utf8), const char* title);   // defined with the emoji sheet below
static void threadSheetIconPicked(const char* g) {
  char nm[UITask::MAX_THREAD_NAME + 1] = "";
  if (!channelLongSheetName(nm, sizeof nm)) return;
  touchPrefsSetChannelEmoji(nm, g);
  g_lv.dirty_threads = true;                       // chat list re-renders the avatar
  if (g_lv.task) g_lv.task->showAlert(TR("Chat icon set"), 1200);
}
static void threadSheetIconCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED) return;
  openEmojiPickerPick(threadSheetIconPicked, "Chat icon");
}
static void threadSheetIconResetCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_LONG_PRESSED) return;
  char nm[UITask::MAX_THREAD_NAME + 1] = "";
  if (!channelLongSheetName(nm, sizeof nm)) return;
  touchPrefsSetChannelEmoji(nm, "");
  g_lv.dirty_threads = true;
  if (g_lv.task) g_lv.task->showAlert(TR("Chat icon reset to letters"), 1400);
}

// Per-thread settings sheet (DM or channel) — opened by long-press AND the per-row gear AND the
// in-channel cog, so all are the SAME screen. Mark-as-read, mute messages / @ mentions, region &
// scope, share secret, blocked users, remove/delete.
// Laid out exactly like the contact long-press sheet (openContactActionSheet): a half-width
// 2-column grid + a full-width danger row, so every action fits on ONE screen — the old 42px
// full-width rows overflowed and scrolled on both S3 boards (7 channel rows = ~380px vs the
// T-Deck's ~206px visible area).
static void openThreadActionSheet(int thread_idx, const char* name, bool is_channel) {
  closeChannelLongSheet();
  s_channel_long_idx = thread_idx;

  s_channel_long_sheet = lv_obj_create(lv_layer_top());
  lv_obj_remove_style_all(s_channel_long_sheet);
  // Backdrop sits below the global status bar — keeps the centered card
  // from being shoved partway behind the time/battery row and lets the
  // bar stay readable while the sheet is open.
  lv_obj_set_size(s_channel_long_sheet, lv_disp_get_hor_res(nullptr),
                  lv_disp_get_ver_res(nullptr) - STATUSBAR_H);
  lv_obj_set_pos(s_channel_long_sheet, 0, STATUSBAR_H);
  lv_obj_set_style_bg_color(s_channel_long_sheet, lv_color_hex(0x000000), LV_PART_MAIN);
  lv_obj_set_style_bg_opa(s_channel_long_sheet, LV_OPA_60, LV_PART_MAIN);
  lv_obj_clear_flag(s_channel_long_sheet, LV_OBJ_FLAG_SCROLLABLE);
  lv_obj_move_foreground(s_channel_long_sheet);
  lv_obj_add_event_cb(s_channel_long_sheet, channelLongSheetDismissCb, LV_EVENT_CLICKED, nullptr);

  // Same metrics as the contact action sheet — the two sheets are siblings and
  // should read identically. (PSC is a no-op on the smaller boards.)
#if CAP_LARGE_SCREEN
  const int card_w  = PSC(232);
  const int btn_h   = PSC(30);
  const int btn_gap = PSC(6);
  const int title_h = PSC(28);
  const int pad     = PSC(6);
  const lv_font_t* row_font = &g_font_14;
#else
  const int card_w  = 232;
  const int btn_h   = 30;
  const int btn_gap = 4;    // 4 (was 6): the 7-item channel grid + danger row must fit the T-Deck's ~206 px
  const int title_h = 28;
  const int pad     = 6;
  const lv_font_t* row_font = &g_font_12;
#endif
  // Room-server thread? Adds the "Log in again" row (issue #89 session recovery).
  bool is_room_thread = false;
  if (!is_channel && g_lv.task) {
    uint8_t rpub[32];
    if (g_lv.task->getThreadContactPub(thread_idx, rpub)) {
      ContactInfo* rc = the_mesh.lookupContactByPubKey(rpub, PUB_KEY_SIZE);
      is_room_thread = (rc && rc->type == ADV_TYPE_ROOM);
    }
  }
  // Everything except Remove/Delete goes in the 2-column grid; the danger row
  // spans the full width at the bottom. Channel: mark-read + region + the two
  // mutes + share + blocked = 6 grid items (3 rows). Room: mark-read +
  // login-again + reset-path + blocked = 4 (2 rows). DM: 3 (2 rows).
  const int grid_items = is_channel ? 7 : (is_room_thread ? 4 : 3);   // channels: +Chat icon
  const int grid_rows  = (grid_items + 1) / 2;          // ceil
  int card_h = title_h + (grid_rows + 1) * (btn_h + btn_gap) + pad;
  const int max_h = lv_disp_get_ver_res(nullptr) - STATUSBAR_H - 12;
  const bool card_scroll = (card_h > max_h);            // safety net only — all three variants fit both S3 boards
  if (card_scroll) card_h = max_h;
  s_chmute_msg_btn = nullptr; s_chmute_men_btn = nullptr;
  lv_obj_t* card = lv_obj_create(s_channel_long_sheet);
  lv_obj_remove_style_all(card);
  lv_obj_set_size(card, card_w, card_h);
  lv_obj_align(card, LV_ALIGN_CENTER, 0, 0);
  lv_obj_set_style_bg_color(card, lv_color_hex(COLOR_PANEL), LV_PART_MAIN);
  lv_obj_set_style_bg_opa(card, LV_OPA_COVER, LV_PART_MAIN);
  lv_obj_set_style_radius(card, 8, LV_PART_MAIN);
  lv_obj_set_style_border_color(card, lv_color_hex(0x18191A), LV_PART_MAIN);
  lv_obj_set_style_border_width(card, 1, LV_PART_MAIN);
  lv_obj_set_style_pad_all(card, pad, LV_PART_MAIN);
  lv_obj_clear_flag(card, LV_OBJ_FLAG_SCROLLABLE);   // header stays fixed; the body below scrolls
  addCloseXBadge(card, channelLongSheetDismissCb);

  lv_obj_t* title = lv_label_create(card);
  char nm[40];
  copyUtf8ReplacingMissingGlyphs(&g_font_14, nm, sizeof(nm), name ? name : "");
  lv_label_set_text_fmt(title, "%s  %s", is_channel ? LV_SYMBOL_LOOP : LV_SYMBOL_ENVELOPE,
                        nm[0] ? nm : (is_channel ? "(channel)" : "(chat)"));
  lv_obj_set_style_text_color(title, lv_color_hex(COLOR_TEXT), LV_PART_MAIN);
  lv_obj_set_style_text_font(title, &g_font_14, LV_PART_MAIN);
  lv_label_set_long_mode(title, LV_LABEL_LONG_DOT);
  // Trim 32 px on the right so long channel names don't slide under the X.
  lv_obj_set_width(title, card_w - 2 * pad - 32);
  lv_obj_set_pos(title, 0, 0);

  // Scrollable body BELOW the fixed title + X header (scroll is a fallback that
  // shouldn't trigger — the grid fits). Buttons are clipped to the body, so the
  // floating X is never drawn on top of one.
  lv_obj_t* body = lv_obj_create(card);
  lv_obj_remove_style_all(body);
  lv_obj_set_pos(body, 0, title_h);
  lv_obj_set_size(body, card_w - 2 * pad, card_h - 2 * pad - title_h);
  lv_obj_set_style_pad_all(body, 0, LV_PART_MAIN);
  if (card_scroll) lv_obj_set_scroll_dir(body, LV_DIR_VER);
  else             lv_obj_clear_flag(body, LV_OBJ_FLAG_SCROLLABLE);

  const int col_gap = btn_gap;
  const int half_w  = (card_w - 2 * pad - col_gap) / 2;
  int y   = 0;
  int col = 0;   // 0 = left column, 1 = right column
  // Half-width grid button; advances column, wrapping to the next row. Labels
  // get DOT-ellipsis so a long translation ("Geblokkeerde gebruikers") degrades
  // gracefully instead of hard-clipping at the cell edge.
  auto mk = [&](const char* lbl, lv_event_cb_t cb, uint32_t bg) -> lv_obj_t* {
    lv_obj_t* b = lv_btn_create(body);
    lv_obj_set_size(b, half_w, btn_h);
    lv_obj_set_pos(b, col == 0 ? 0 : (half_w + col_gap), y);
    styleButton(b);
    lv_obj_set_style_pad_ver(b, 0, LV_PART_MAIN);
    lv_obj_set_style_pad_hor(b, 4, LV_PART_MAIN);
    if (bg) lv_obj_set_style_bg_color(b, lv_color_hex(bg), LV_PART_MAIN);
    lv_obj_add_event_cb(b, cb, LV_EVENT_CLICKED, nullptr);
    lv_obj_t* l = lv_label_create(b);
    lv_label_set_text(l, TR(lbl));
    lv_obj_set_style_text_font(l, row_font, LV_PART_MAIN);
    lv_label_set_long_mode(l, LV_LABEL_LONG_DOT);
    lv_obj_set_width(l, half_w - 8);
    lv_obj_set_style_text_align(l, LV_TEXT_ALIGN_CENTER, LV_PART_MAIN);
    lv_obj_center(l);
    if (col == 0) col = 1;
    else { col = 0; y += btn_h + btn_gap; }
    return b;
  };
  // Full-width danger row (Remove/Delete). Closes any half-open grid row first.
  auto mk_full = [&](const char* lbl, lv_event_cb_t cb, uint32_t bg) {
    if (col == 1) { col = 0; y += btn_h + btn_gap; }
    lv_obj_t* b = lv_btn_create(body);
    lv_obj_set_size(b, card_w - 2 * pad, btn_h);
    lv_obj_set_pos(b, 0, y);
    styleButton(b);
    lv_obj_set_style_pad_ver(b, 0, LV_PART_MAIN);
    lv_obj_set_style_pad_hor(b, 8, LV_PART_MAIN);
    if (bg) lv_obj_set_style_bg_color(b, lv_color_hex(bg), LV_PART_MAIN);
    lv_obj_add_event_cb(b, cb, LV_EVENT_CLICKED, nullptr);
    lv_obj_t* l = lv_label_create(b);
    lv_label_set_text(l, TR(lbl));
    lv_obj_set_style_text_font(l, row_font, LV_PART_MAIN);
    lv_obj_center(l);
    y += btn_h + btn_gap;
  };
  mk(LV_SYMBOL_OK "  Mark as read", threadSheetMarkReadCb, 0);
  if (is_channel) {
    mk(LV_SYMBOL_SETTINGS "  Region & scope", channelLongSheetRegionCb, 0);
    // The two mutes sit side by side on their own row; labels set by chmuteRefreshLabels().
    s_chmute_msg_btn = mk("", channelMuteMsgCb, 0);
    s_chmute_men_btn = mk("", channelMuteMenCb, 0);
    chmuteRefreshLabels();
    mk(LV_SYMBOL_SHUFFLE  "  Share secret",   channelLongSheetShareCb,   0);
    mk(LV_SYMBOL_CLOSE    "  Blocked users",  channelLongSheetBlockedCb, 0);
    // Chat-list avatar emoji: tap = pick, long-press = back to the two-letter auto avatar.
    lv_obj_t* icb = mk(LV_SYMBOL_IMAGE "  Chat icon", threadSheetIconCb, 0);
    if (icb) lv_obj_add_event_cb(icb, threadSheetIconResetCb, LV_EVENT_LONG_PRESSED, nullptr);
    mk(LV_SYMBOL_TRASH    "  Delete history", threadSheetClearHistCb,    0);
    mk_full(LV_SYMBOL_TRASH "  Remove channel", channelLongSheetDeleteCb, 0xB23A48);
  } else {
    if (is_room_thread)
      mk(LV_SYMBOL_REFRESH "  Log in again",  threadSheetRoomLoginCb,    0);
    mk(LV_SYMBOL_LOOP     "  Reset path",     threadSheetResetPathCb,    0);
    mk(LV_SYMBOL_CLOSE    "  Blocked users",  channelLongSheetBlockedCb, 0);
    mk(LV_SYMBOL_TRASH    "  Delete history", threadSheetClearHistCb,    0);
    mk_full(LV_SYMBOL_TRASH "  Delete chat",   threadSheetDeleteDmCb,     0xB23A48);
  }
}

static void chatDeleteApply() {
  if (!g_lv.task || s_chat_del_thread_idx < 0) return;
  const int idx = s_chat_del_thread_idx;
  const bool is_channel = s_chat_del_is_channel;
  s_chat_del_thread_idx = -1;

  // For a channel thread we also drop the slot from the_mesh's channel
  // table so the same secret doesn't keep matching new floods. For a DM
  // thread we just drop the UI-side thread; the contact stays in the
  // Contacts tab and can be removed there separately if the user wants.
  int channel_slot = -1;
  if (is_channel) {
    bool ch; uint16_t unread; uint32_t ts;
    char name[UITask::MAX_THREAD_NAME + 1];
    if (g_lv.task->getThreadInfo(idx, ch, unread, ts, name, sizeof(name)) && ch) {
#ifdef MAX_GROUP_CHANNELS
      ChannelDetails cd{};
      // Prefer the thread's own pinned slot — validated by name at use time (a
      // stale slot index must never delete a DIFFERENT channel, see the
      // channel-send stale-slot bug). Truncation-tolerant compare: the thread
      // name is capped at MAX_THREAD_NAME, so match only that many chars.
      const int16_t pinned = g_lv.task->threadMeshChannelSlot(idx);
      if (pinned >= 0 && pinned < MAX_GROUP_CHANNELS &&
          the_mesh.getChannel(pinned, cd) && cd.name[0] &&
          strncmp(cd.name, name, UITask::MAX_THREAD_NAME) == 0) {
        channel_slot = pinned;
      } else {
        for (int i = 0; i < MAX_GROUP_CHANNELS; ++i) {
          if (the_mesh.getChannel(i, cd) && cd.name[0] &&
              strncmp(cd.name, name, UITask::MAX_THREAD_NAME) == 0) {
            channel_slot = i;
            break;
          }
        }
      }
#endif
    }
  }

  if (!g_lv.task->removeThread(idx)) {
    g_lv.task->showAlert(TR("Couldn't delete"), 1200);
    return;
  }
  if (is_channel && channel_slot >= 0) {
    the_mesh.uiDeleteChannel(channel_slot);
  }
  g_lv.dirty_threads = true;
  g_lv.task->showAlert(is_channel ? TR("Channel removed") : TR("Chat removed"), 1000);
}

static void threadLongPressCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_LONG_PRESSED || !g_lv.task) return;
  auto* ctx = static_cast<LvThreadButtonCtx*>(lv_event_get_user_data(e));
  if (!ctx) return;
  bool ch; uint16_t unread; uint32_t ts;
  char name[UITask::MAX_THREAD_NAME + 1] = "";
  if (!g_lv.task->getThreadInfo(ctx->idx, ch, unread, ts, name, sizeof(name))) return;
  // Swallow the rest of this gesture so the matching CLICKED that LVGL
  // would otherwise fire on release doesn't also open the chat behind the
  // confirm popup.
  lv_indev_t* act = lv_indev_get_act();
  if (act) lv_indev_wait_release(act);

  s_chat_del_thread_idx = ctx->idx;
  s_chat_del_is_channel = ch;

  // Both DMs and channels get an action sheet: Mark as read, plus manage
  // (channels: Share secret / Remove; DMs: Delete chat).
  openThreadActionSheet(ctx->idx, name, ch);
}

// Per-row gear: opens the SAME thread-settings sheet as a long-press (and as the in-chat cog).
static void threadGearCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  auto* ctx = static_cast<LvThreadButtonCtx*>(lv_event_get_user_data(e));
  if (!ctx) return;
  lv_indev_t* act = lv_indev_get_act();
  if (act) lv_indev_wait_release(act);   // swallow the gesture so the row's CLICKED doesn't open the chat
  bool ch; uint16_t un; uint32_t ts; char name[UITask::MAX_THREAD_NAME + 1] = "";
  if (!g_lv.task->getThreadInfo(ctx->idx, ch, un, ts, name, sizeof(name))) return;
  s_chat_del_thread_idx = ctx->idx; s_chat_del_is_channel = ch;
  openThreadActionSheet(ctx->idx, name, ch);
}

static void threadSelectCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  auto* ctx = static_cast<LvThreadButtonCtx*>(lv_event_get_user_data(e));
  if (!ctx) return;
  LvChatPanel& p = ctx->channel ? g_lv.ch : g_lv.dm;
  g_lv.task->enterThread(ctx->channel, ctx->idx);
  // Update header name
  bool ch; uint16_t unread; uint32_t ts; char name[UITask::MAX_THREAD_NAME + 1];
  if (g_lv.task->getThreadInfo(ctx->idx, ch, unread, ts, name, sizeof(name))) {
    char san[UITask::MAX_THREAD_NAME + 8];
    copyUtf8ReplacingMissingGlyphs(&g_font_12, san, sizeof(san), name);
    setChatStatusTitle(san);   // thread name → status bar (no in-chat header bar)
  }
  p.detail_open = true;
  hideKb();
  if (p.overlay) {
    lv_obj_clear_flag(p.overlay, LV_OBJ_FLAG_HIDDEN);
    lv_obj_move_foreground(p.overlay);
  }
  // Build + scroll AFTER un-hiding: bubbles measured in a hidden tree get a wrong height,
  // which collapses the content so the open-scroll lands at the top. Visible first = correct
  // heights = the open-scroll reaches the newest message.
  refreshChatDetailAsync(p);
#if defined(HAS_TDECK_KEYBOARD) || defined(HAS_M9_KEYBOARD)
  // Physical keyboard: focus the composer on open so typing goes straight in.
  showKb(&p);
#endif
}

static void sendFromPanelCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  auto* p = static_cast<LvChatPanel*>(lv_event_get_user_data(e));
  if (!p || !p->composer_ta) return;
  const char* text = lv_textarea_get_text(p->composer_ta);
  if (!text || !text[0]) return;
  hideKb();
  g_lv.task->setComposerMode(true);
  g_lv.task->composerReset();
  for (const char* cp = text; *cp; ++cp) g_lv.task->composerAppendChar(*cp);
  if (g_lv.task->composerSend()) {
    lv_textarea_set_text(p->composer_ta, "");
    refreshChatDetailAsync(*p);
    g_lv.dirty_threads = true;
  }
}

