// ---- Discovered list modal: shows adverts NOT yet in contacts[], with "Add" buttons ----
struct DiscoveredAddCtx { int slot_idx; };
static DiscoveredAddCtx s_disc_add_ctx[DISCOVERED_MAX];

// Forward declared so discoveredAddCb can re-open the list after a successful add.
static void openDiscoveredModalCb(lv_event_t* e);

// ---- Discovered-list sort (mirrors the Contacts sort) -------------------------
// Recently heard / Name / Distance, each with an ascending/descending toggle.
// "Recent message" is contacts-only (discovered nodes have no message history) so
// it's omitted. Distance excludes entries that have shared no location.
enum DiscSortMode : uint8_t {
  DISC_SORT_RECENT   = 0,   // newest advert first (default)
  DISC_SORT_AZ       = 1,   // name A-Z
  DISC_SORT_DISTANCE = 2,   // nearest first; no-location entries excluded
  DISC_SORT_COUNT    = 3,
};
static uint8_t g_disc_sort      = DISC_SORT_RECENT;
static bool    g_disc_sort_desc = false;
static const char* discSortOptName(uint8_t m) {
  switch (m) {
    case DISC_SORT_RECENT:   return "Recently heard";
    case DISC_SORT_AZ:       return "Name (A-Z)";
    case DISC_SORT_DISTANCE: return "Nearest first";
  }
  return "?";
}
// True if discovered entry ia sorts before ib for the current mode + direction.
// `prim` < 0 = a before b in the mode's natural order; g_disc_sort_desc flips it.
static bool discSortBefore(int ia, int ib, double self_lat, double self_lon) {
  const LvDiscoveredEntry& A = s_discovered[ia];
  const LvDiscoveredEntry& B = s_discovered[ib];
  int prim = 0;
  switch (g_disc_sort) {
    case DISC_SORT_DISTANCE: {
      const double da = contactDistanceKm(self_lat, self_lon, A.ci.gps_lat / 1.0e6, A.ci.gps_lon / 1.0e6);
      const double db = contactDistanceKm(self_lat, self_lon, B.ci.gps_lat / 1.0e6, B.ci.gps_lon / 1.0e6);
      if (da < db) prim = -1; else if (da > db) prim = 1;
      break;
    }
    case DISC_SORT_AZ:
      prim = strcasecmp(A.ci.name, B.ci.name);
      break;
    default:   // DISC_SORT_RECENT — newest first
      if (A.recv_ms != B.recv_ms) prim = (A.recv_ms > B.recv_ms) ? -1 : 1;
      break;
  }
  if (prim == 0) prim = strcasecmp(A.ci.name, B.ci.name);   // tiebreak by name
  if (g_disc_sort_desc) prim = -prim;
  return prim < 0;
}
static void openDiscSortSheetCb(lv_event_t* e);   // sort button -> sheet (defined with the Contacts sheets)

static void discoveredAddCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED || !g_lv.task) return;
  auto* ctx = static_cast<DiscoveredAddCtx*>(lv_event_get_user_data(e));
  if (!ctx) return;
  int idx = ctx->slot_idx;
  if (idx < 0 || idx >= DISCOVERED_MAX) return;
  LvDiscoveredEntry& e_disc = s_discovered[idx];
  if (!e_disc.used) return;

  // Add the captured ContactInfo straight to the_mesh.
  if (the_mesh.addContact(e_disc.ci)) {
    the_mesh.uiPersistContacts();   // write /contacts3 so the add survives reboot
    e_disc.in_contacts = true;
    markDiscoveredDirty();
    refreshContactsList();          // rebuild the Contacts tab now (count changed) so the
                                    // new contact shows without needing a tab reload
    g_lv.task->showAlert(TR("Added to contacts"), 1000);
    // Re-open the Discovered modal so the list updates immediately.
    closeSettingsModal();
    lv_event_t synth{};
    synth.code = LV_EVENT_CLICKED;
    openDiscoveredModalCb(&synth);
  } else {
    g_lv.task->showAlert(TR("Contacts full"), 1200);
  }
}

static void discoveredPurgeApply() {
  purgeDiscovered();
  saveDiscovered();   // persist the cleared list immediately
  closeSettingsModal();
  lv_event_t synth{};
  synth.code = LV_EVENT_CLICKED;
  openDiscoveredModalCb(&synth);   // re-open so the list shows the now-empty state
}
static void discoveredPurgeCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED) return;
  showConfirm(TR("Purge all discovered nodes?"), TR("Purge"), discoveredPurgeApply);
}

// ---- Discovered settings (cogwheel): a small sheet floated over the modal ----
static lv_obj_t* s_disc_settings_root = nullptr;
static void closeDiscoveredSettings() {
  if (s_disc_settings_root) {
    hideKb();   // dismiss the keyboard before the bound hop-limit textarea is freed
    popupClose(&s_disc_settings_root);
  }
}
static void discSettingsDismissCb(lv_event_t* e) {
  if (lv_event_get_code(e) != LV_EVENT_CLICKED) return;
  lv_indev_t* act = lv_indev_get_act(); if (act) lv_indev_wait_release(act);
  const bool changed = discoveredSweepHops();   // apply the hop limit to existing entries
  closeDiscoveredSettings();
  if (changed) {   // re-render the Discovered list so the removed (over-limit) nodes disappear
    closeSettingsModal();
    lv_event_t synth{}; synth.code = LV_EVENT_CLICKED;
    openDiscoveredModalCb(&synth);
  }
}
