    y += settingsRowLabel(body, y, 0, TR("Custom UTC offset (hours)"), COLOR_SUB, &g_font_12, 0) + 2;

    lv_obj_t* bminus = lv_btn_create(body);
    lv_obj_set_size(bminus, SC(50), SC(34));
    lv_obj_set_pos(bminus, 2, y);
