#if defined(HAS_TDECK_GT911) || defined(HELTEC_LORA_V4_TFT)
// ---- ST7789 panel sleep (anti burn-in) -------------------------------------
// Backlight-off alone is NOT screen-off: the ST7789 keeps refreshing the same
// static image behind the dark backlight, continuously biasing the liquid
// crystals — which is what actually sticks an image into the LCD (Kaj +
// wyvern.red burn-in reports). The core driver's Adafruit object is private and
// wraps no sleep API (and the T-Deck has no TFT reset line, PIN_TFT_RST=-1), so
// send the one-byte ST7789 commands ourselves on the same HSPI bus + CS/DC pins
// the driver uses. SLPIN stops the oscillator, booster and LC drive; panel RAM
// is RETAINED, so wake = SLPOUT + DISPON and the old image is back with no
// redraw. Safe alongside LVGL: flushes run on this same task (no concurrent
// bus use), and the datasheet allows memory writes while asleep.
static void touchPanelCmd(uint8_t cmd) {
  static SPIClass* s_cmd_spi = nullptr;
  if (!s_cmd_spi) {
    s_cmd_spi = new SPIClass(HSPI);                       // same port as the driver's displaySPI
    s_cmd_spi->begin(PIN_TFT_SCL, -1, PIN_TFT_SDA, -1);   // same pins; re-init is idempotent
  }
  s_cmd_spi->beginTransaction(SPISettings(8000000, MSBFIRST, SPI_MODE0));
  digitalWrite(PIN_TFT_DC, LOW);    // command
  digitalWrite(PIN_TFT_CS, LOW);
  s_cmd_spi->transfer(cmd);
  digitalWrite(PIN_TFT_CS, HIGH);
  digitalWrite(PIN_TFT_DC, HIGH);   // back to data (the driver's idle default)
  s_cmd_spi->endTransaction();
}
static void touchPanelSleep(bool slp) {
  static bool s_asleep = false;
  if (slp == s_asleep) return;
  s_asleep = slp;
  if (slp) {
    touchPanelCmd(0x28);   // DISPOFF — blank the output
    touchPanelCmd(0x10);   // SLPIN — stop oscillator/booster/LC drive (RAM retained)
    delay(5);              // t_SLPIN: bus must stay quiet 5 ms
  } else {
    touchPanelCmd(0x11);   // SLPOUT — RAM was retained through sleep
    delay(6);              // datasheet: >=5 ms before the next command
    touchPanelCmd(0x29);   // DISPON — the pre-sleep image reappears
  }
}
#else
static inline void touchPanelSleep(bool) {}
#endif

/* Screen sleep = backlight off + ST7789 sleep-in (not a full panel reset).
 * Panel RAM survives SLPIN, so wake is near-instant and the previous image is
 * still on the glass when the LED lights back up — no partial re-render. */
static inline void touchScreenBacklight(bool on) {
#if defined(TLORA_PAGER)
  // Also has TFT_BL defined (=-1, disabling TFT_eSPI's own backlight pin
  // support), which would otherwise fall into the #elif defined(TFT_BL) branch
  // below and digitalWrite a "-1" pin -- must come first. touchPanelSleep()
  // has no ST7796-specific implementation (falls to the no-op default below,
  // same as Tanmatsu), so screen-sleep here is backlight-off only, not a real
  // panel sleep command -- a known, low-severity gap, not a regression (this
  // board never had panel-sleep to begin with).
  if (on) { touchPanelSleep(false); display.setBrightness(s_brightness_pct); }
  else    { display.setBrightness(0); touchPanelSleep(true); }
#elif defined(HAS_BACKLIGHT_PWM)
  // Both touch boards drive the backlight via LEDC PWM on PIN_TFT_LEDA_CTL once
  // applyBrightness() has claimed the pin at boot. A plain digitalWrite would
  // then be a no-op (on the V4, TFT_BL == PIN_TFT_LEDA_CTL == GPIO21), so drive
  // the PWM duty directly: 0 = off, saved brightness = on.
  if (!s_bl_pwm_ready) applyBrightness(s_brightness_pct);   // ensure LEDC is attached
  if (on) touchPanelSleep(false);   // wake the panel BEFORE lighting it (old frame intact)
  ledcWrite(kBlPwmChannel, on ? ((uint32_t)s_brightness_pct * 255u / 100u) : 0u);
  if (!on) touchPanelSleep(true);   // then stop the panel driving the crystals (anti burn-in)
#elif defined(TFT_BL)
  pinMode(TFT_BL, OUTPUT);
  #ifdef TFT_BACKLIGHT_ON
    digitalWrite(TFT_BL, on ? TFT_BACKLIGHT_ON : !TFT_BACKLIGHT_ON);
  #else
    digitalWrite(TFT_BL, on ? HIGH : LOW);
  #endif
#elif defined(HAS_TANMATSU)
  // Tanmatsu: the screen backlight is the CH32-driven display backlight (not LEDC / TFT_BL). Off = a
  // true 0 duty; on = restore the saved brightness. Without this, idle-off + sleep set _screen_off
  // but the panel never actually went dark (this branch used to be the (void)on no-op).
  if (on) applyBrightness(s_brightness_pct);
  else    bsp_display_set_backlight_brightness(0);
#elif defined(HAS_THINKNODE_M9)
  // M9: BL_EN (GPIO17) drives a PNP transistor gate — LEDC PWM works (confirmed on hardware,
  // Specter bring-up), but duty is INVERTED vs. a normal N-channel/NPN setup: lower duty on
  // the base = MORE conduction = brighter. applyBrightness() below already accounts for this.
  if (on) applyBrightness(s_brightness_pct);
  else    ledcWrite(kM9BlPwmChannel, 255);   // inverted: 255 = 0% conduction = off
#else
  (void)on;
#endif
}

#if defined(ESP32)
// Drop the CPU clock while the screen is off to save power. The LoRa radio RX,
// Wi-Fi and BLE all keep working at 80 MHz (the Wi-Fi floor), so the node never
// stops listening to the mesh — we just stop burning 240 MHz to render nothing.
// Restored to 240 MHz on wake so tile decode / rendering stays fast. Only
// switches when the target changes (the call is a hard DFS switch).
static void setCpuForScreen(bool screen_on) {
  static int s_cur_mhz = 240;
  const int want = screen_on ? 240 : 80;
  if (want == s_cur_mhz) return;
  setCpuFrequencyMhz(want);
  s_cur_mhz = want;
}
#else
static inline void setCpuForScreen(bool) {}
#endif

void UITask::noteUserInput() {
  /* Called from touch input. If the screen was explicitly locked via the
   * BOOT button, ignore touches entirely — only a BOOT button press can
   * release that. Idle-timeout locks still unlock on touch. */
  if (_screen_off && _manual_lock) return;
  _last_input_ms = millis();
  if (_screen_off) wakeScreen();
}

void UITask::wakeScreen() {
  if (!_screen_off) return;
  setCpuForScreen(true);     // back to 240 MHz before we render
  touchScreenBacklight(true);
  _screen_off    = false;
  _manual_lock   = false;
  _last_input_ms = millis();
}

void UITask::lockScreen() {
  // Backlight off + manual lock so touch is ignored (noteUserInput()
  // early-returns) until a deliberate unlock.
#if defined(HAS_TANMATSU)
  // Tanmatsu: a Vol- LONG-press locks. Light the screen + build/show the lock-screen overlay (so the
  // wallpaper + clock are visible the moment you lock) and block app input (_manual_lock). Another
  // long Vol- press unlocks; the idle timeout still dims the backlight while locked.
  _manual_lock = true;
  _screen_off  = false;
  setCpuForScreen(true);
  touchScreenBacklight(true);
  lockscreenShow();
  _lock_lit_ms   = millis();   // arm the burn-in guard — a lit lock screen always dims, even at timeout "never"
  _last_input_ms = millis();
  return;
#endif
  touchScreenBacklight(false);
  setCpuForScreen(false);    // screen dark -> drop to 80 MHz
  _screen_off  = true;
  _manual_lock = true;
#if defined(HAS_TDECK_GT911)
  // T-Deck: build the lock screen overlay now (dark). A key/trackball press
  // reveals it; holding the trackball unlocks. (V4 keeps the plain off+wake.)
  lockscreenShow();
  _lock_lit_ms = millis();   // arm the burn-in guard so a lit lock screen always dims (#55)
#endif
}

void UITask::lockscreenReveal() {
#if CAP_LOCK_SCREEN
  if (!_manual_lock) return;
  if (_screen_off) {
    lockscreenShow();               // build + foreground FIRST
    lv_refr_now(nullptr);           // force it to actually paint before the backlight comes on
    setCpuForScreen(true); touchScreenBacklight(true); _screen_off = false;
    _lock_lit_ms = millis();
  } else {
    lockscreenShow();                // already lit: just re-foreground (idempotent, cheap)
  }
  _last_input_ms = millis();
#endif
}

void UITask::unlockScreen() {
  _manual_lock = false;
  _screen_off  = false;
  setCpuForScreen(true);
  touchScreenBacklight(true);
#if CAP_LOCK_SCREEN
  lockscreenHide();
#endif
  _last_input_ms = millis();
}

// Tanmatsu Vol- LONG-press handler: toggle the hard (overlay) screen lock.
void UITask::toggleScreenLock() {
  if (_manual_lock) unlockScreen();
  else              lockScreen();
}

// Tanmatsu Vol- SHORT-click / idle-dim: soft screen sleep — backlight off, NOT hard-locked, so any
// key (or another Vol- click) wakes it. Like the V4 user button, minus the touch-block (no touch here).
void UITask::sleepScreen() {
  if (_screen_off) return;
  touchScreenBacklight(false);
  setCpuForScreen(false);   // screen dark -> drop to 80 MHz
  _screen_off = true;
}

uint16_t UITask::getScreenTimeoutSecs() const {
#if defined(ESP32)
  return touchPrefsGetScreenTimeoutSecs();
#else
  return _screen_timeout_ms / 1000;
#endif
}

bool UITask::setScreenTimeoutSecs(uint16_t seconds) {
#if defined(ESP32)
  if (!touchPrefsSetScreenTimeoutSecs(seconds)) return false;
#endif
  _screen_timeout_ms = static_cast<uint32_t>(seconds) * 1000u;
  _last_input_ms = millis();
  return true;
}

bool UITask::sendAdvertNow() { return the_mesh.advert(); }
bool UITask::sendAdvertFlood() { return the_mesh.sendAdvert(true); }
bool UITask::sendAdvertZeroHop() { return the_mesh.sendAdvert(false); }
// Signal probe: ask the nearest repeater to reply (a directed trace, never a flood)
// so the live signal reading updates from a real link measurement. If no repeater
// with a known path is available, fall back to a zero-hop advert (announce ourselves;
// passive RX still updates the signal from any directly-heard neighbour).
bool UITask::sendSignalProbe() {
  if (the_mesh.uiSendSignalProbe() != 0) return true;
  return the_mesh.sendAdvert(false);
}

// Two writers interleaving on the history file would corrupt it: wait out an
// in-flight worker flush (bounded; worst observed SPIFFS GC ~6-8 s) and cancel
// a pending one. Returns true if a pending flush was cancelled — its snapshot
// was never written, so the caller must treat the ring as dirty and write it.
static bool uiHistWaitWorkerIdle() {
  const bool cancelled = s_hist_flush_req;
  s_hist_flush_req = false;
  const uint32_t t0 = millis();
  while (s_hist_flush_busy && (uint32_t)(millis() - t0) < 9000) delay(10);
  return cancelled;
}

bool UITask::enableBle() {
  if (!_serial) return false;
#if defined(ESP32)
  // Same thresholds as the boot-time co-init guard (main.cpp) — keep in sync.
  const size_t BLE_COEXIST_MIN_FREE  = 50u * 1024u;
  const size_t BLE_COEXIST_MIN_BLOCK = 20u * 1024u;
  if (ESP.getFreeHeap() < BLE_COEXIST_MIN_FREE || ESP.getMaxAllocHeap() < BLE_COEXIST_MIN_BLOCK)
    return false;
#endif
  _serial->enableBle();
  return true;
}

void UITask::persistHistoryNow() {
  uiHistWaitWorkerIdle();   // writes below cover strictly newer data
  saveThreadsToStorage();
  saveMsgsToStorage();
}

void UITask::rebootDevice() {
  // Persist chat history synchronously before we reboot — the periodic
  // flush is rate-capped, so without this a reboot could drop the most
  // recent chat history.
  if (uiHistWaitWorkerIdle()) _msgs_dirty = true;   // cancelled snapshot = unwritten data
  if (_threads_dirty) saveThreadsToStorage();
  if (_msgs_dirty) saveMsgsToStorage();
  discoveredFlushNow();   // persist the Discovered ring before we go down
  the_mesh.flushContactsIfDirty();   // and any coalesced contacts refresh (card-less devices)
  if (_board) _board->reboot();
}

void UITask::msgRead(int msgcount) { _msgcount = msgcount; }

// Shared core for newMsg / newMsgFromPubWithMeta. Bundles the channel-vs-DM
// sender parsing + thread routing in one place so the meta-aware path doesn't
// drift from the plain path. `meta_flags` is 0 (no RX metadata) when called
// from base newMsg; the touch UI ignores zero-meta entries in the Info popup.
void UITask::newMsgImpl(uint8_t path_len, const char* from_name, const char* text, int msgcount,
                        uint8_t meta_flags, int8_t snr_q4, int8_t rssi,
                        const char* sender_override) {
  (void)path_len;
  _msgcount = msgcount;
  const bool have_sender_override = (sender_override && sender_override[0]);
  bool channel = (g_last_event == UIEventType::channelMessage);
  const char* thread = channel
      ? (from_name && from_name[0] ? from_name : "#unknown")
      : (from_name && from_name[0] ? from_name : "Unknown");

  // For channel/group messages the on-wire `text` is "SenderName: body" —
  // split that so the bubble can show the sender as a small label and the
  // body as the message. DMs already arrive with the sender as from_name.
  // Parsed up here (before the chime) so a blocked sender can be dropped first.
  char parsed_sender[MAX_SENDER_NAME + 1];
  parsed_sender[0] = '\0';
  const char* body = text ? text : "";
  if (channel && text && !have_sender_override) {
    const char* colon = strstr(text, ": ");
    if (colon) {
      int slen = static_cast<int>(colon - text);
      if (slen > 0 && slen <= MAX_SENDER_NAME) {
        strncpy(parsed_sender, text, slen);
        parsed_sender[slen] = '\0';
        body = colon + 2;
      }
    }
  }
  const char* sender = have_sender_override
      ? sender_override
      : (channel
      ? (parsed_sender[0] ? parsed_sender : (from_name && from_name[0] ? from_name : "node"))
      : (from_name && from_name[0] ? from_name : "node"));

#if defined(ESP32)
  // Blocked-by-name sender: a channel/room bot we have no pubkey to target via
  // the prefix ignore-list (room posts carry only a display name). Drop the post
  // entirely — no bubble, no notification, no chime. Set from the message
  // long-press "Block" when the sender isn't a saved contact (gubbinsgalore's
  // self-advertising room bot).
  if (channel && touchPrefsIsNameIgnored(sender)) return;
#endif

#if defined(HAS_UI_SOUND) || defined(HAS_TANMATSU)
  // Notification chime (T-Deck I2S speaker / Heltec V4 piezo / Tanmatsu I2S codec).
  // @-mentions get a distinct sound + their own enable, so an operator can mute message
  // sounds but still hear @-mentions. Each respects the per-channel mute flags.
  {
    const bool is_mention = channel && text && textMentionsMe(text);
    const bool is_dm = (g_last_event == UIEventType::contactMessage);   // private/direct message
    const uint8_t cmute = channel ? touchPrefsGetChannelMute(thread) : 0;
    if (!isBuzzerQuiet()) {   // master Sound switch: off = silent, overrules everything
      if (is_mention && touchPrefsGetSoundMentions() && !(cmute & TOUCH_CHMUTE_MEN)) uiPlaySlot(TOUCH_SND_MEN);
      else if (is_dm) { if (touchPrefsGetSoundDirect()) uiPlaySlot(TOUCH_SND_DM); }
      else if (touchPrefsGetSoundMessages() && !(cmute & TOUCH_CHMUTE_MSG))          uiPlaySlot(TOUCH_SND_MSG);
    }
  }
#endif
  // Inbound route (repeater hashes) for the Info popup — flood RX only; read
  // synchronously from MyMesh, which stashed it just before this call.
  uint8_t in_path[MAX_UI_PATH];
  uint8_t in_path_n = 0;
  uint16_t in_scope = 0;
  if ((meta_flags & MSG_META_HAS_RX) && (meta_flags & MSG_META_IS_FLOOD)) {
    in_path_n = the_mesh.lastRxPath(in_path, sizeof(in_path));
    bool has_scope = false;
    in_scope = the_mesh.lastRxScope(&has_scope);
    if (has_scope) meta_flags |= MSG_META_HAS_SCOPE;
  }
  const int msg_slot = _ui_msg_head;   // appendMessage writes _ui_msgs[head], then advances head
  appendMessage(thread, sender, body, channel, false, true,
                0 /*ack_hash*/, DELIV_NONE,
                meta_flags, path_len, snr_q4, rssi,
                in_path_n ? in_path : nullptr, in_path_n, 0 /*sent_fp*/, in_scope);
  // Stamp the bubble with the sender's embedded send-time (stashed by MyMesh::
  // queueMessage) instead of "now" — fixes room-server history replay showing the
  // whole batch at the delivery time. Only override with a real epoch; live DMs
  // (embedded ts ≈ now) are unaffected. Consume-once so it never leaks to the next.
  {
    uint32_t emb_ts = the_mesh.uiConsumeLastSenderTs();
    if (emb_ts > 1700000000) _ui_msgs[msg_slot].ts = emb_ts;
  }
  syncThreadMeshSlots(thread, channel);
#if defined(HAS_TDECK_GT911)
  // Mirror incoming traffic into the terminal live feed (only while it's open).
  // Runs on the mesh thread (core 1, same as the UI loop) so the append is safe.
  if (s_term_log_box) {
    char line[200];
    const bool  has_snr = (meta_flags & MSG_META_HAS_RX);
    const float snr     = snr_q4 / 4.0f;
    if (channel) {
      if (has_snr) snprintf(line, sizeof line, "RX [%s] %s: %s  (snr %.1f)", thread, sender, body, snr);
      else         snprintf(line, sizeof line, "RX [%s] %s: %s", thread, sender, body);
      termLogAppendC(TERM_C_RX_CH, nullptr, line);
    } else {
      if (has_snr) snprintf(line, sizeof line, "RX %s: %s  (snr %.1f)", sender, body, snr);
      else         snprintf(line, sizeof line, "RX %s: %s", sender, body);
      termLogAppendC(TERM_C_RX_DM, nullptr, line);
    }
  }
#endif
#if defined(HAS_TOUCH_UI)
  g_lv.dirty_threads  = true;
  g_lv.dirty_timeline = true;
#endif
}

void UITask::newMsgFromPub(uint8_t path_len, const uint8_t* from_pub, const char* from_name, const char* text, int msgcount) {
  if (from_pub && touchPrefsIsIgnored(from_pub)) return;   // blocked sender — drop (no chat entry, no notify)
  newMsg(path_len, from_name, text, msgcount);
  if (!from_pub || !from_name || !from_name[0]) return;
  const int t = findThreadByName(from_name, false);
  if (t < 0) return;
  _ui_threads[t].mesh_contact_idx = -1;
  memcpy(_ui_threads[t].mesh_contact_pub, from_pub, PUB_KEY_SIZE);
  memcpy(_ui_threads[t].mesh_contact_key6, from_pub, 6);
  if (!_ui_threads[t].channel && t == _active_thread_idx) {
    _active_dm_contact_set = true;
    memcpy(_active_dm_contact_pub, from_pub, sizeof(_active_dm_contact_pub));
  }
  syncThreadMeshSlots(from_name, false);
}

void UITask::newMsgFromPubWithMeta(uint8_t path_len, bool is_flood,
                                   const uint8_t* from_pub, const char* from_name,
                                   const char* text, int msgcount,
                                   int8_t snr_q4, int8_t rssi) {
  if (from_pub && touchPrefsIsIgnored(from_pub)) return;   // blocked sender — drop (no chat entry, no notify)
  const uint8_t meta_flags = MSG_META_HAS_RX | (is_flood ? MSG_META_IS_FLOOD : 0);
  newMsgImpl(path_len, from_name, text, msgcount, meta_flags, snr_q4, rssi);
  // Mirror newMsgFromPub's contact-pub plumbing so the newly-arrived DM
  // resolves back to its contact entry for replies.
  if (!from_pub || !from_name || !from_name[0]) return;
  const int t = findThreadByName(from_name, false);
  if (t < 0) return;
  _ui_threads[t].mesh_contact_idx = -1;
  memcpy(_ui_threads[t].mesh_contact_pub, from_pub, PUB_KEY_SIZE);
  memcpy(_ui_threads[t].mesh_contact_key6, from_pub, 6);
  if (!_ui_threads[t].channel && t == _active_thread_idx) {
    _active_dm_contact_set = true;
    memcpy(_active_dm_contact_pub, from_pub, sizeof(_active_dm_contact_pub));
  }
  syncThreadMeshSlots(from_name, false);
}

void UITask::newRoomMsgFromPubWithMeta(uint8_t path_len, bool is_flood,
                                       const uint8_t* from_pub, const char* from_name,
                                       const char* author_name,
                                       const char* text, int msgcount,
                                       int8_t snr_q4, int8_t rssi) {
  if (from_pub && touchPrefsIsIgnored(from_pub)) return;   // blocked room — drop
  const uint8_t meta_flags = MSG_META_HAS_RX | (is_flood ? MSG_META_IS_FLOOD : 0);
  // The thread is the room (from_name); the per-message sender label is the
  // resolved author. g_last_event is roomMessage here, so newMsgImpl keeps the
  // thread DM-style (channel=false) — matching the thread the user opens by
  // tapping the room contact — while the timeline shows the author label for
  // room threads (thread_is_room).
  newMsgImpl(path_len, from_name, text, msgcount, meta_flags, snr_q4, rssi, author_name);
  // Map the room thread back to the room contact so replies/login resolve.
  if (!from_pub || !from_name || !from_name[0]) return;
  const int t = findThreadByName(from_name, false);
  if (t < 0) return;
  _ui_threads[t].mesh_contact_idx = -1;
  memcpy(_ui_threads[t].mesh_contact_pub, from_pub, PUB_KEY_SIZE);
  memcpy(_ui_threads[t].mesh_contact_key6, from_pub, 6);
  if (!_ui_threads[t].channel && t == _active_thread_idx) {
    _active_dm_contact_set = true;
    memcpy(_active_dm_contact_pub, from_pub, sizeof(_active_dm_contact_pub));
  }
  syncThreadMeshSlots(from_name, false);
}

void UITask::appSentMsgToContact(const uint8_t* to_pub, const char* to_name, const char* text,
                                 uint32_t ack_hash, uint32_t sent_fp) {
  if (!to_name || !to_name[0] || !text || !text[0]) return;
  const char* sender = (_node_prefs && _node_prefs->node_name[0]) ? _node_prefs->node_name : "me";
  // Mirror an app-originated DM as a local outgoing bubble in the recipient's thread (#46) — the
  // on-device UI is otherwise the only message consumer that never sees sends made from the
  // companion app. appendMessage creates the thread if it doesn't exist and refreshes the view.
  // sent_fp links a locally-originated send (web/terminal) to the repeats-heard ring (0 = none).
  appendMessage(to_name, sender, text, false /*channel*/, true /*outgoing*/, false /*mark_unread*/,
                ack_hash, DELIV_SENT, 0, 0, 0, 0, nullptr, 0, sent_fp);
  // Lock the thread to the contact's pubkey so a reply typed on-device resolves it (mirrors the
  // receive path above).
  const int t = findThreadByName(to_name, false);
  if (t < 0 || !to_pub) return;
  _ui_threads[t].mesh_contact_idx = -1;
  memcpy(_ui_threads[t].mesh_contact_pub, to_pub, PUB_KEY_SIZE);
  memcpy(_ui_threads[t].mesh_contact_key6, to_pub, 6);
  if (!_ui_threads[t].channel && t == _active_thread_idx) {
    _active_dm_contact_set = true;
    memcpy(_active_dm_contact_pub, to_pub, sizeof(_active_dm_contact_pub));
  }
  syncThreadMeshSlots(to_name, false);
}

void UITask::appSentMsgToChannel(const char* channel_name, const char* text, uint32_t sent_fp) {
  if (!channel_name || !channel_name[0] || !text || !text[0]) return;
  const char* sender = (_node_prefs && _node_prefs->node_name[0]) ? _node_prefs->node_name : "me";
  // Mirror an app-originated channel message as a local outgoing bubble in the channel thread — the
  // channel-send command otherwise never tells the on-device UI about companion sends (the DM path
  // does, via appSentMsgToContact above). appendMessage creates the thread + refreshes the view.
  // sent_fp links a locally-originated send (web/terminal) to the repeats-heard ring (0 = none).
  appendMessage(channel_name, sender, text, true /*channel*/, true /*outgoing*/, false /*mark_unread*/,
                0 /*ack_hash*/, DELIV_SENT, 0, 0, 0, 0, nullptr, 0, sent_fp);
}

void UITask::newMsg(uint8_t path_len, const char* from_name, const char* text, int msgcount) {
  newMsgImpl(path_len, from_name, text, msgcount, 0 /*meta_flags*/, 0 /*snr*/, 0 /*rssi*/);
}

void UITask::notify(UIEventType t) {
  g_last_event = t;
  // A discovered/added contact should refresh the Contacts list even mid-frame and
  // even while a companion app is connected (issue #73). Flag it; UITask::loop does
  // the rebuild on the LVGL thread (refreshContactsList no-op's when nothing changed).
  if (t == UIEventType::newContactMessage) s_ct_contacts_dirty = true;
  const char* msg = nullptr;
  switch (t) {
    case UIEventType::contactMessage:    msg = TR("New DM");          break;
    case UIEventType::channelMessage:    msg = TR("New channel msg");  break;
    case UIEventType::roomMessage:       msg = TR("New room msg");     break;
    case UIEventType::newContactMessage: msg = TR("New contact");      break;
    case UIEventType::ack:               showAlert(TR("Delivered"), 900); return;
    default: return;
  }
#if defined(HAS_TANMATSU)
  // Pulse the envelope-icon LED for an actual incoming message (contact discovery is too spammy).
  if (t == UIEventType::contactMessage || t == UIEventType::channelMessage || t == UIEventType::roomMessage)
    msgLedFlash();
#endif
#if defined(HAS_TDECK_KEYBOARD)
  // Same idea on the T-Deck (no notification LED): wake the screen + briefly light the keyboard.
  if (touchPrefsGetMsgFlash() &&
      (t == UIEventType::contactMessage || t == UIEventType::channelMessage || t == UIEventType::roomMessage)) {
    s_msgflash_until = millis() + 1600;
    s_msgflash_wake  = true;
  }
#endif
  // Background traffic (also reflected in the tab badges): show a subtle, low-key
  // chip rather than the prominent centre alert toast, so it's less intrusive.
  // New-contact discovery can be spammy in a busy mesh, so its chip is opt-out in
  // Settings -> Auto-add; when suppressed we still log the diag line + tab badge.
  const bool toast = (t != UIEventType::newContactMessage) || touchPrefsGetNewContactToast();
  if (toast) {
    strncpy(_alert, msg, sizeof(_alert) - 1);
    _alert[sizeof(_alert) - 1] = '\0';
    _alert_expiry = millis() + 1100UL;
  }
#if defined(HAS_TOUCH_UI)
  pushDiagLine(msg);
  if (toast) showSubtleNotifyLvgl(msg, 1100);
#endif
}

// ============================================================
// UITask::loop
// ============================================================
// ---- beta_31 field-freeze tracer (diagnostics only, no behaviour change) ----
// Any instrumented main-loop section that blocks >200 ms lands in this ring,
// printed to Serial as [STALL] and listed at the bottom of Settings -> About so
// a field tester can simply photograph the screen. uiCp() checkpoints attribute
// a slow UITask::loop pass to the section that actually ate the time.
StallRec g_stall_ring[16];   // struct defined above sysInfoText (About shows the ring)
uint8_t  g_stall_cnt = 0, g_stall_w = 0;
void stallLog(const char* tag, uint32_t dur_ms) {
  if (dur_ms < 200) return;
  g_stall_ring[g_stall_w] = { (uint32_t)(millis() / 1000u), (uint16_t)(dur_ms > 65535 ? 65535 : dur_ms), tag };
  g_stall_w = (uint8_t)((g_stall_w + 1) % 16);
  if (g_stall_cnt < 16) g_stall_cnt++;
  Serial.printf("[STALL] %s %lums\n", tag, (unsigned long)dur_ms);
}
const char*   g_ui_stall_tag = "";     // slowest section of the current UITask::loop pass
uint16_t      g_ui_stall_max = 0;
static const char*  s_ui_cp_tag = "";
static uint32_t     s_ui_cp_t0  = 0;
static inline void uiCp(const char* next) {
  const uint32_t nowms = millis();
  const uint32_t dt = nowms - s_ui_cp_t0;
  if (dt > g_ui_stall_max) { g_ui_stall_max = (uint16_t)(dt > 65535 ? 65535 : dt); g_ui_stall_tag = s_ui_cp_tag; }
  s_ui_cp_tag = next;
  s_ui_cp_t0  = nowms;
}

void UITask::loop() {
  unsigned long now = millis();
#if !defined(HAS_TANMATSU)
  // REMOTE mode: draw/refresh the physical-panel placeholder (first pass via the IP
  // sentinel, then whenever the IP changes), and clear the bootloop guard once this
  // boot has run a few seconds (proving it came up cleanly).
  if (s_remote_mode) {
    if (s_rmt_boot_guard && now > 8000) s_rmt_boot_guard = 0;
    // Rotate button on the web page -> flip orientation by rebooting into the other axis.
    if (uint8_t oreq = g_web_mirror.takeOrient()) {
      const bool want_land = (oreq == 1);
      if (want_land != s_remote_landscape) {
        touchPrefsSetRemoteLandscape(want_land);
        if (g_lv.task) { g_lv.task->showAlert(TR("Rotating - reconnecting..."), 1600); g_lv.task->rebootDevice(); }
      }
    }
    if (s_remote_exit_armed && (now - s_remote_exit_armed) >= 3000) { s_remote_exit_armed = 0; drawRemotePlaceholder(false); }
    // Exit button on the web page -> leave remote mode (board-agnostic; the main way out
    // for keyboard-less boards like the Heltec V4).
    if (g_web_mirror.takeExit()) { touchPrefsSetRemoteMode(false); if (g_lv.task) g_lv.task->rebootDevice(); }
#if CAP_TOUCH
    remoteTouchTick();   // 3 s touch-and-hold on the panel also leaves remote (no SPACE key)
#endif
    uint32_t rip = (WiFi.status() == WL_CONNECTED) ? (uint32_t)WiFi.localIP() : 0;
    if (rip != s_remote_ph_ip) drawRemotePlaceholder();
  }
  // Web mesh terminal: run any command the browser typed through the exact same dispatch
  // as the on-device console (chat commands else the config CLI). Output streams back via
  // the termLogAppendC hook. Own the CLI sink while active + the on-device console isn't open.
  if (g_web_mirror.terminalOn() && s_term_log_box == nullptr) {
    MyMesh::setTerminalSink(&terminalSink);   // idempotent; routes config-CLI/async replies to the web
    char tcmd[256];
    while (g_web_mirror.popTermCmd(tcmd, sizeof tcmd)) {
      // '@'-prefixed lines are the Contacts/Chats data API (JSON back over the data channel);
      // everything else is a terminal command (browser echoes it locally, so don't echo back).
      if (handleWebDataCmd(tcmd)) continue;
      if (!terminalRunChatCommand(tcmd)) the_mesh.runLocalCli(tcmd);
    }
    // Live receive: a mesh callback flagged new/changed messages -> nudge the web client (single-producer here).
    if (s_web_rx_nudge) { s_web_rx_nudge = false; g_web_mirror.pushTermData("{\"t\":\"rx\"}"); }
    // Periodic status bar refresh (battery / wifi / clock / signal / unread) for the web header.
    static uint32_t s_web_status_next = 0;
    if ((int32_t)(millis() - s_web_status_next) >= 0) { s_web_status_next = millis() + 3000; webPushStatus(); }
  }
#endif
  g_ui_stall_max = 0; g_ui_stall_tag = ""; s_ui_cp_tag = "ui:head"; s_ui_cp_t0 = now;
#if defined(ESP32)
  // Persist the clock floor every 15 min (small prefs-blob write; SdNvsPrefs
  // rewrites a file on the Launcher-SD backend, so keep the cadence low). Power
  // loss costs at most this window of floor progress — a soft reset keeps the
  // ESP32 RTC domain ticking, so only true power-off needs the persisted copy.
  { static unsigned long s_floor_due = 0;
    if (now >= s_floor_due) {
      s_floor_due = now + 15UL * 60UL * 1000UL;
      touchPrefsSetClockFloor(rtc_clock.getFloor());   // no-op unless it grew
    } }
#endif
#if defined(DOC_CAPTURE)
  // One-shot: once the boot splash is gone, wait for the host to send 'G' (scripts/doc/capture.py),
  // then walk every screen and stream each framebuffer over USB. The 'G' handshake avoids a
  // flash-vs-connect timing race — the host can attach whenever and trigger the tour.
  { static bool s_doc_done = false;
    if (!s_doc_done && s_splash_root == nullptr) {
      while (Serial.available()) { if (Serial.read() == 'G') { s_doc_done = true; docCaptureTour(); break; } }
    } }
#endif
  // Safety net: the Spectrum app borrows the radio (s_spectrum_active pauses
  // the_mesh.loop() in main.cpp). Its close paths all restore + clear the flag,
  // but if the page ever vanished without that, the mesh would stay off the
  // radio forever — so re-apply the mesh params and release ownership here.
  if (s_spectrum_active && !s_spec_root) spectrumRestoreRadio();
  uiCp("ui:hist");
  flushHistoryIfDue(now);
  uiCp("ui:ctdirty");
  // A contact was discovered/updated via an advert — possibly while a companion app was connected
  // over BLE (issue #73). FORCE the rebuild: an advert can fill in a name, or refresh an existing
  // (or app-added) contact, WITHOUT changing getNumContacts() — which the count-cached
  // refreshContactsList() would no-op, leaving the node invisible until a manual re-sort (exactly the
  // "only shows when I sort by messages received" report). Keep the flag set until we're actually on
  // the Contacts tab so an advert heard on another tab isn't dropped, and coalesce an advert flood to
  // at most one rebuild per ~350 ms.
  if (s_ct_contacts_dirty && getActiveTab() == CONTACTS_TAB_INDEX) {
    static unsigned long s_ct_dirty_refresh_ms = 0;
    // 2.5 s coalescing (was 350 ms): a full rebuild costs ~1.3 s at ~570 contacts
    // (#82), so an advert flood must not be able to queue them back to back. The
    // flag stays set, so the last advert in a burst still lands within 2.5 s.
    if ((now - s_ct_dirty_refresh_ms) > 2500) {
      s_ct_contacts_dirty   = false;
      s_ct_dirty_refresh_ms = now;
      contactsListForceRefresh();   // bypass the count-cache — a name-fill / re-advert doesn't change the count
    }
  }
  // Safety net (#73): some contact mutations never set the dirty flag above — messaging a not-yet-
  // added node creates an anon contact (core addContact), the companion app imports one over BLE
  // (CMD_ADD_UPDATE_CONTACT), a delete removes one. getNumContacts() is O(1), so cheaply catch ANY
  // count change while the Contacts tab is visible and rebuild, independent of adverts.
  {
    static int s_ct_seen_count = -1;
    if (getActiveTab() == CONTACTS_TAB_INDEX) {
      const int nct = the_mesh.getNumContacts();
      if (nct != s_ct_seen_count) { s_ct_seen_count = nct; refreshContactsList(); }
    }
  }
#if defined(HAS_TANMATSU)
  if (s_msgled_flash_until) msgLedRefresh(getUnreadTotal() > 0);   // end the one-shot envelope-LED flash on time
#endif
  { static bool s_disc_loaded = false; if (!s_disc_loaded) { s_disc_loaded = true; loadDiscovered(); } }
  uiCp("ui:disc");
  discoveredFlushIfDue(now);   // persist the discovered ring (rate-capped) so it survives reboot
  uiCp("ui:gps");
  updateGpsLocation(now);   // sync + persist node location from GPS once fixed
  ++s_live_diag_loops;
  if (_alert_expiry != 0 && now >= _alert_expiry) {
    _alert[0]     = '\0';
    _alert_expiry = 0;
  }
  /* UI ping timeout: if no reply arrived in UI_PING_TIMEOUT_MS, show a
   * "No reply" toast and clear the pending state in MyMesh so a stale match
   * doesn't fire later. */
  if (s_ui_ping_deadline_ms != 0 && now >= s_ui_ping_deadline_ms) {
    s_ui_ping_deadline_ms = 0;
    the_mesh.cancelUIPingPending();
    char msg[64];
    snprintf(msg, sizeof(msg), TR("No reply from %s"), s_ui_ping_target_name);
    showAlert(msg, 3500);
  }
#if CAP_SD
  // Manual telemetry request timed out — flip the open window to "failed" (it
  // still shows the history). Auto-poll has no deadline, so it never lands here.
  if (s_telem_manual_pending && s_telem_deadline_ms != 0 && now >= s_telem_deadline_ms) {
    s_telem_manual_pending = false;
    s_telem_deadline_ms = 0;
    the_mesh.cancelUIDeferredLogin();   // drop a not-yet-acked LOGIN so a late OK can't fire a stale REQ
    the_mesh.cancelUIPingPending();     // drop the pending reply tag if the REQ was already sent
    if (s_telemetry_root) openTelemetryWindow(s_telem_node, s_telem_name, TELEM_FAILED);
  }
#endif

  /* User button (BOOT / PIN_USER_BTN): press toggles the screen. When the
   * panel is off it wakes + resets the idle timer; when on it locks
   * immediately. Active-low with internal pullup.
   *
   * IMPORTANT: GPIO0 is the BOOT strapping pin — if the user held it during
   * a manual flash, it's still LOW for ~hundreds of ms after reset, and a
   * naive edge detect (`prev=HIGH` default) would fire a spurious "press"
   * on the first loop iter and manual-lock the screen. We sample the real
   * state once on first entry so a held BOOT doesn't trigger a fake edge. */
#ifdef PIN_USER_BTN
  {
    static bool s_user_btn_inited = false;
    static uint8_t s_user_btn_prev = HIGH;
    if (!s_user_btn_inited) {
      s_user_btn_prev = digitalRead(PIN_USER_BTN);
      s_user_btn_inited = true;
    }
    uint8_t v = digitalRead(PIN_USER_BTN);
#if CAP_TRACKBALL
    /* On the T-Deck, PIN_USER_BTN (GPIO0) is the trackball centre click — make
     * it act as a touch at the cursor: a held click = a held press (so taps,
     * long-press and drag all work), released = released. While the screen is
     * off a click only wakes it, and is NOT delivered as a tap. */
    const bool tb_pressed = (v == LOW);
    // Swallow the click that unlocks the screen: without this, the SAME held
    // click is re-injected as a cursor tap on the next iteration (once the
    // screen is back on), which clicks the UI underneath — the "flash" on
    // unlock. Consume it until the button is released.
    static bool s_tb_wake_consume = false;
    static unsigned long s_tb_hold_start = 0;   // press timestamp for hold-to-unlock
    if (_manual_lock) {
      // Hard-locked: a press reveals the lock screen (lights it); HOLDING the
      // trackball for kLockUnlockHoldMs unlocks. A short tap just lights it.
      if (tb_pressed && s_user_btn_prev == HIGH) {
        lockscreenReveal();          // light the lock screen, don't unlock
        s_tb_hold_start = now;
      }
      if (tb_pressed && s_tb_hold_start && !_screen_off) {
        const unsigned long held = now - s_tb_hold_start;
        if (held >= kLockUnlockHoldMs) {
          unlockScreen();            // hides the "Unlocking…" popup too
          s_tb_hold_start = 0;
          s_tb_wake_consume = true;  // swallow the release so it isn't a UI tap
        } else if (held >= 200) {    // ignore a quick wake-tap; show on a real hold
          lockscreenUnlockProgress(kLockUnlockHoldMs - held);
        }
      }
      if (!tb_pressed) { s_tb_hold_start = 0; lockscreenUnlockPopupHide(); }  // released early -> cancel
      s_tb_click_press = false;      // never deliver clicks as taps while locked
    } else if (_screen_off) {
      if (tb_pressed && s_user_btn_prev == HIGH) { wakeScreen(); s_tb_wake_consume = true; }
      s_tb_click_press = false;
    } else if (s_emoji_sheet) {
      // Emoji picker open: a fresh press inserts the highlighted glyph via the
      // selector instead of injecting a cursor tap. Edge-triggered so a held
      // click doesn't repeat-insert.
      if (tb_pressed && s_user_btn_prev == HIGH) {
        emojiSelectorClick();
        s_tb_last_active_ms = now; noteUserInput();
      }
      s_tb_click_press = false;
    } else {
      if (!tb_pressed) s_tb_wake_consume = false;   // released after unlock -> clicks re-armed
      s_tb_click_press = tb_pressed && !s_tb_wake_consume;
      if (s_tb_click_press) { s_tb_last_active_ms = now; noteUserInput(); }
    }
#elif defined(HAS_RAK_TAP_V2)
    // RAK Tap V2: single BOOT button (GPIO0), no trackball, no keyboard.
    // Short press (<1s): toggle screen on/off (does NOT hard-lock -- touch
    //   can still wake, since there is no second button for unlock).
    // Long press (>=1s): open power menu (Power off / Reboot / Cancel).
    static unsigned long s_rak_btn_down_ms = 0;
    static bool s_rak_long_fired = false;
    if (v == LOW && s_user_btn_prev == HIGH) {
      s_rak_btn_down_ms = now;
      s_rak_long_fired  = false;
    } else if (v == LOW && s_user_btn_prev == LOW) {
      if (now - s_rak_btn_down_ms >= 1000 && !s_rak_long_fired) {
        s_rak_long_fired = true;
        if (_screen_off) wakeScreen();
        openPowerMenu();
      }
    } else if (v == HIGH && s_user_btn_prev == LOW) {
      if (!s_rak_long_fired) {
        if (_screen_off) { wakeScreen(); }
        else {
          touchScreenBacklight(false);
          setCpuForScreen(false);
          _screen_off = true;
          // NO _manual_lock -- touch can still wake the screen.
        }
      }
    }
#else   // Generic: Heltec V4 -- short press toggles screen + lock
    if (v == LOW && s_user_btn_prev == HIGH) {
      if (_screen_off) {
#if defined(TLORA_PAGER)
        /* Pager only: hard-locked means BOOT is a no-op -- holding Backspace
         * is the deliberate unlock gesture (updatePagerBackspaceUnlockHold).
         * A plain idle-dimmed (not manually locked) screen still wakes on
         * BOOT exactly as before. NOT applied to the V4 below (#else of this
         * #if), which has no keyboard -- BOOT is its only lock/unlock control
         * and must keep instantly unlocking it. */
        if (!_manual_lock) wakeScreen();
#else
        /* wakeScreen() clears _manual_lock so subsequent touches work. */
        wakeScreen();
#endif
      } else {
        touchScreenBacklight(false);
        setCpuForScreen(false);
        _screen_off  = true;
        _manual_lock = true;  // touch cannot unlock until BOOT pressed again
      }
    }
#endif
    s_user_btn_prev = v;
  }
#endif
#ifdef PIN_AUX_BTN
  {
    static bool s_aux_btn_inited = false;
    static uint8_t s_aux_btn_prev = HIGH;
    if (!s_aux_btn_inited) {
      s_aux_btn_prev = digitalRead(PIN_AUX_BTN);
      s_aux_btn_inited = true;
    }
    uint8_t v = digitalRead(PIN_AUX_BTN);
    if (v == LOW && s_aux_btn_prev == HIGH) {
      noteUserInput();
      /* For now the aux button just wakes the screen — separate action
       * (e.g. send advert, cycle tab) can be wired here later. */
    }
    s_aux_btn_prev = v;
  }
#endif

  /* Screen timeout: toggle just the backlight (not the TFT RST/SPI) when idle
   * for `_screen_timeout_ms`. 0 disables auto-off. */
  // Signed compare: input handlers earlier in THIS loop iteration (the trackball
  // click block, aux button) call noteUserInput() with a fresh millis() that can
  // be a few ms AFTER `now` (sampled at the top of loop()). An unsigned compare
  // then made (now - _last_input_ms) underflow to ~4.29e9 and fire the timeout on
  // every click. Signed keeps a slightly-ahead stamp negative (= "just had input").
  if (_screen_timeout_ms > 0 && !_screen_off &&
      (int32_t)(now - _last_input_ms) >= (int32_t)_screen_timeout_ms) {
    if (s_lock_on_screen_off && !_manual_lock) {
      // "Lock when screen off": idle dim also hard-locks, so the touchscreen is
      // inert until a deliberate unlock (trackball hold on the T-Deck, BOOT
      // press on the V4) — Tim's request to stop pocket-taps while dark. The
      // !_manual_lock guard stops the Tanmatsu's lit lock screen from re-firing
      // lockScreen() (and re-lighting) on every idle tick.
      lockScreen();
    } else {
      touchScreenBacklight(false);
      setCpuForScreen(false);   // idle dim (no lock) -> drop to 80 MHz too
      _screen_off = true;
    }
  }

  // Burn-in guard (#55): a LIT hard-locked panel ALWAYS dims after a bounded window — independent of
  // the screen-timeout setting (which may be "never") and of held / ghost touches that keep re-revealing
  // the lock screen. _lock_lit_ms is re-armed only on a real off->lit transition (lock / reveal), so it
  // can't be pushed out forever; a deliberate reveal re-lights it and it dims again shortly after.
  // Was T-Deck-only; now every board — the Tanmatsu's lit lock screen otherwise never went dark at
  // screen-timeout "never" (wyvern.red burn-in report). No-op where _lock_lit_ms is never armed (V4).
  if (_manual_lock && !_screen_off && _lock_lit_ms) {
    uint32_t lock_dim = (_screen_timeout_ms > 0 && _screen_timeout_ms < 20000u) ? _screen_timeout_ms : 20000u;
    if ((int32_t)(now - _lock_lit_ms) >= (int32_t)lock_dim) {
      touchScreenBacklight(false);
      setCpuForScreen(false);
      _screen_off = true;
    }
  }

#if defined(HAS_TDECK_KEYBOARD)   // notify-flash (and so the notify wake) is a T-Deck feature
  // Notify-wake re-dim: a screen lit by a MESSAGE (not user input) goes dark again after a
  // short bounded window. On a busy channel the per-message wakes otherwise keep a static
  // image lit for the full screen-timeout — or forever at "never" — which retains into the
  // LCD (wyvern.red burn-in report). Any real input inside the window hands back to the
  // normal timeout. Set in the msgflash consumer below AFTER wakeScreen()/lockscreenReveal()
  // stamp _last_input_ms, so "input newer than the stamp" means the user, not the wake.
  if (s_notify_wake_ms) {
    if (_screen_off)                          s_notify_wake_ms = 0;   // already dark again
    else if (_last_input_ms > s_notify_wake_ms) s_notify_wake_ms = 0; // user took over
    else if ((int32_t)(now - s_notify_wake_ms) >= 10000) {
      s_notify_wake_ms = 0;
      touchScreenBacklight(false);
      setCpuForScreen(false);
      _screen_off = true;
    }
  }
#endif  // HAS_TDECK_KEYBOARD (notify-wake re-dim)

#if defined(HAS_TOUCH_UI)
  if (!g_lv.ready) return;

#if CAP_TOUCH
  // The Tanmatsu has NO CHSC6x cap-touch — input comes from the bsp keypad (LVGL KEYPAD indev).
  // heltecV4CapTouchBegin() probes CHSC6x I2C addresses on arduino Wire (port 0), which badge-bsp
  // already owns for its CH32V203 coprocessor; the failed i2c_new_master_bus/release there breaks
  // the coprocessor bus and kills the keyboard. Since touch never inits (no chip), this retried
  // every loop and disrupted I2C continuously. Skip all cap-touch hardware on this board.
  if (!g_lv.touch_inited) {
    g_lv.touch_inited = heltecV4CapTouchBegin();
    // Surface the one-shot I2C bus-scan result to the Set-tab diag ring exactly
    // once (Begin runs the scan on its first call; the string is stable after).
    static bool s_touch_scan_logged = false;
    if (!s_touch_scan_logged) {
      s_touch_scan_logged = true;
      pushDiagLine(heltecV4CapTouchDebug());
    }
    if (g_lv.touch_inited) {
      pushDiagLine("touch init ok");
      // Once hardware is up, hand the chsc6x poll off to a pinned task on
      // core 0 so it runs at a fixed ~125 Hz independent of LVGL render and
      // the_mesh.loop() — that's the only way touch stays snappy when the
      // mesh stack bursts. Falls back to inline polling in lvglTouchRead if
      // task creation fails.
      if (heltecV4CapTouchStartBackgroundPoll(8)) {
        pushDiagLine("touch async @ 125 Hz");
      } else {
        pushDiagLine("touch async start failed");
      }
    } else if (!g_cap_touch_hw_started) {
      g_cap_touch_hw_started = true;
      pushDiagLine("touch init retrying");
    }
  }
#endif  // !HAS_TANMATSU (cap-touch hardware init)

  // Swipe → tab change (blocked while a chat detail overlay is open)
  int8_t swipe_x = 0, swipe_y = 0;
  if (heltecV4CapTouchPopSwipe(&swipe_x, &swipe_y)) {
    applySwipeGesture(swipe_x, swipe_y);
  }

  // Advance LVGL tick using micros so timers still run when millis() does not advance.
  // With LV_TICK_CUSTOM=1 (lv_conf.h) LVGL reads esp_timer_get_time() itself and
  // lv_tick_inc isn't declared — keep the manual path compiled out so the build
  // works either way.
#if !LV_TICK_CUSTOM
  {
    const uint32_t t_us = micros();
    if (t_us < g_lv.lvgl_tick_prev_us) {
      g_lv.lvgl_tick_prev_us = t_us;
    } else {
      uint32_t add_ms = (t_us - g_lv.lvgl_tick_prev_us) / 1000U;
      if (add_ms > 500U) add_ms = 500U;
      if (add_ms > 0) {
        lv_tick_inc(add_ms);
        g_lv.lvgl_tick_prev_us += add_ms * 1000U;
      }
    }
  }
#endif

  // A repeater echo of one of our sent floods was just counted — repaint the
  // open chat so the sent bubble's repeat tag ticks up live.
  if (the_mesh.takeEchoDirty()) {
    g_lv.dirty_timeline = true;
#if !defined(HAS_TANMATSU)
    s_web_rx_nudge = true;   // repeat-heard tag ticked up -> refresh the web chat too
#endif
  }

  bool heavy_ok = !g_lv.defer_heavy_refresh || now >= g_lv.heavy_refresh_at_ms;
  if (g_lv.defer_heavy_refresh && heavy_ok) g_lv.defer_heavy_refresh = false;

  if (g_lv.dirty_threads && heavy_ok) {
    refreshThreadLists();
    g_lv.dirty_threads = false;
  }
  if (g_lv.dirty_timeline && heavy_ok) {
    // Only repaint the detail that is currently open.
    if (g_lv.dm.detail_open) refreshChatDetailAsync(g_lv.dm);
    if (g_lv.ch.detail_open) refreshChatDetailAsync(g_lv.ch);
    g_lv.dirty_timeline = false;
  }
  // Jump arrows dim to 50% one second after the last scroll activity (every
  // scroll tick re-brightens them via chatUpdateJumpButtons).
  if (!s_jump_dimmed && s_jump_active_ms &&
      (uint32_t)(millis() - s_jump_active_ms) > 1000) {
    if (g_lv.dm.detail_open)      jumpBtnsSetDim(&g_lv.dm, true);
    else if (g_lv.ch.detail_open) jumpBtnsSetDim(&g_lv.ch, true);
    else                          s_jump_dimmed = true;   // nothing open: park the state
  }
#if CAP_SD || defined(TLORA_PAGER)
  // microSD insert/remove detection — only while the file manager is open, so
  // there's no idle SPI traffic. SD.begin runs on this loop task (never
  // concurrent with the radio's SPI), and reuses the radio's already-begun bus.
  if (s_fm_list) {
    static unsigned long s_sd_poll_next = 0;
    if (now >= s_sd_poll_next) {
      s_sd_poll_next = now + 2000;
      if (!s_sd_mounted) {
        // Only re-probe after the backoff window — repeatedly re-initing an
        // unmountable card spikes current / churns the bus and can reset the board.
        if (now >= s_sd_retry_after_ms && fmSdTryMount()) {
          showAlert(TR("SD card inserted"), 1500);
          if (!s_fm_fs) fmShowRoots();          // refresh roots so it appears
        }
      } else if (SD.cardType() == CARD_NONE) {
        fmSdUnmount();
        showAlert(TR("SD card removed"), 1500);
        if (s_fm_fs == &SD || !s_fm_fs) fmShowRoots();
      }
    }
  }
#endif

  if (now >= _next_mesh_thread_refresh) {
    /* Pick up contact / channel additions that came in from the companion
     * serial client (CMD_SET_CHANNEL etc.). 4 s is the backstop — the app
     * also explicitly pings the UI via onThreadsChanged() for instant pickup. */
    _next_mesh_thread_refresh = now + 4000;
    refreshThreadsFromMesh();
    g_lv.dirty_threads  = true;
  }
  if (now >= _next_refresh) {
    refreshStatusLabels();
    // Unread-count badge over the Chats tab icon (bottom bar).
    if (s_chat_unread_badge) {
      const int u = getUnreadTotal();
      if (u > 0) {
        char b[8]; if (u > 99) snprintf(b, sizeof b, "99+"); else snprintf(b, sizeof b, "%d", u);
        lv_label_set_text(s_chat_unread_badge, b);
        lv_obj_clear_flag(s_chat_unread_badge, LV_OBJ_FLAG_HIDDEN);
      } else {
        lv_obj_add_flag(s_chat_unread_badge, LV_OBJ_FLAG_HIDDEN);
      }
    }
#if defined(HAS_TANMATSU)
    msgLedRefresh(getUnreadTotal() > 0);   // envelope LED: breathe green when unread, dark when caught up
#endif
    // Discovered-count badge on the Contacts-tab "Discovered" button.
    if (s_ct_disc_badge) {
      const int dc = discoveredCount();
      if (dc > 0) {
        char b[8];
        if (dc >= DISCOVERED_MAX) snprintf(b, sizeof b, "%d!", dc);   // ring full
        else                      snprintf(b, sizeof b, "%d", dc > 99 ? 99 : dc);
        lv_label_set_text(s_ct_disc_badge, b);
        lv_obj_clear_flag(s_ct_disc_badge, LV_OBJ_FLAG_HIDDEN);
      } else {
        lv_obj_add_flag(s_ct_disc_badge, LV_OBJ_FLAG_HIDDEN);
      }
    }
    _next_refresh = now + UI_REFRESH_MS;
  }
#if CAP_TRACKBALL
  updateTrackball(now);
#elif defined(HAS_PAGER_ENCODER)
  updatePagerEncoder(now);
#endif
#if defined(HAS_TDECK_KEYBOARD)
  // Drain physical-keyboard presses buffered by the touch task into the field.
  for (int kbi = 0; kbi < 12; ++kbi) {
    int key = tdeckKeyboardReadKey();
    if (key <= 0) break;
    if (!_screen_off) s_kb_last_key_ms = now;   // a keypress while locked must not light the kb
    if (s_remote_mode) { remotePhysicalKey(key); continue; }   // remote mode: physical keys are the exit
    handleHwKey(key);
  }
  // Focusing a text field (cursor starts blinking — tapped or auto-focused)
  // counts as activity, exactly like a keypress: it bumps the timer so the auto
  // backlight lights up and then fades on the same idle window.
  {
    static lv_obj_t* s_kb_prev_ta = nullptr;
    lv_obj_t* cur_ta = g_lv.keyboard ? lv_keyboard_get_textarea(g_lv.keyboard) : nullptr;
    if (cur_ta && cur_ta != s_kb_prev_ta) s_kb_last_key_ms = now;
    s_kb_prev_ta = cur_ta;
  }
  // Keyboard backlight: off / on / auto (lit after activity, off after idle).
  uint8_t kb_bl = 0;
  if (s_kb_bl_mode == 1) kb_bl = tdeckKbBlLevel();
  else if (s_kb_bl_mode == 2 && (now - s_kb_last_key_ms) < kKbBacklightIdleMs) kb_bl = tdeckKbBlLevel();
  if (_screen_off || _manual_lock) kb_bl = 0;   // dark/locked screen -> keep the keyboard dark too
  // New-message notify flash: light the screen so the user sees a message arrived. When the
  // screen is hard-locked, REVEAL the lock screen (lights the wallpaper, keeps the lock) rather
  // than wakeScreen() — wakeScreen() clears _manual_lock, which would leave the lock overlay up
  // but the trackball hold-to-unlock inert (the "can't unlock after a message; have to re-lock
  // with space first" bug). Only an unlocked idle-dim gets the full wake + keyboard pulse.
  if (s_msgflash_wake) {
    s_msgflash_wake = false;
    if (_manual_lock)          { lockscreenReveal(); s_notify_wake_ms = millis(); }  // locked: light wallpaper, keep the lock
    else if (_screen_off)      { wakeScreen();       s_notify_wake_ms = millis(); }  // idle-dimmed: normal wake
    // Stamped AFTER the wake fns set _last_input_ms, so only LATER real input reads
    // as "user took over" and cancels the short notify re-dim window (see loop above).
  }
  if (!_screen_off && !_manual_lock && s_msgflash_until && (int32_t)(now - s_msgflash_until) < 0) kb_bl = tdeckKbBlLevel();
  tdeckKeyboardSetBacklight(kb_bl);
  serviceLockscreen();            // refresh the lock-screen clock on minute roll-over
  serviceLockingCountdown(now);   // advance / fire the spacebar "Locking…" countdown
#elif defined(HAS_PAGER_KEYBOARD)
  // No separate core-0 touch task to own the I2C bus (no touch at all), so poll
  // and drain right here, once per tick. Space press-and-hold locks the screen
  // (updatePagerSpaceHold); Backspace press-and-hold unlocks it again
  // (updatePagerBackspaceUnlockHold) -- the latter must run unconditionally,
  // BEFORE the isScreenOff() split below, since it has to keep working while
  // the screen is dark. updatePagerKbBacklight() is the same story -- it has
  // to force the backlight dark the instant the screen goes off/locked, so it
  // runs unconditionally too, rather than being skipped like the awake-only
  // helpers in the else branch below.
  pagerKeyboardPoll();
  updatePagerBackspaceUnlockHold(now);
  updatePagerKbBacklight(now);
  if (g_lv.task && g_lv.task->isScreenOff()) {
    // Same rationale as updatePagerEncoder(): no touch/trackball wake path on
    // this board, so a keypress while idle-dimmed just wakes the screen
    // instead of being silently swallowed (which is what handleHwKey()'s own
    // isScreenOff() guard does on every other board -- fine there since they
    // always have touch or the trackball to wake with instead). Drain the
    // whole batch so nothing queued here leaks through as real input on the
    // very next tick right after waking.
    bool any = false;
    for (int kbi = 0; kbi < 12; ++kbi) {
      if (pagerKeyboardReadKey() <= 0) break;
      any = true;
    }
    // Discard any Alt tap / Alt+Shift / Alt+Backspace chord picked up while
    // idle-dimmed -- none of them may fire (NEXT / Caps toggle / jump Home)
    // the instant the screen wakes.
    pagerKeyboardConsumeAltTap();
    pagerKeyboardConsumeAltShiftChord();
    pagerKeyboardConsumeAltBackspaceChord();
    // Hard-locked: an ordinary keypress must NOT wake/unlock -- only holding
    // Backspace does (updatePagerBackspaceUnlockHold, already polled above).
    if (any && !g_lv.task->isManualLock()) g_lv.task->wakeScreen();
  } else {
    for (int kbi = 0; kbi < 12; ++kbi) {
      int key = pagerKeyboardReadKey();
      if (key <= 0) break;
      handleHwKey(key);
    }
    updatePagerAltTapNext();
    updatePagerAltShiftChord();
    updatePagerAltBackspaceChord();
    updatePagerBackspaceHold(now);
    updatePagerSpaceHold(now);
  }
#elif defined(HAS_M9_KEYBOARD)
  // M9's keyboard controller is on its OWN bus (Wire1) — no touch task shares
  // it, so polling happens right here on the UI thread rather than from a
  // separate core-0 task. No keyboard-backlight control exists on this
  // controller (TODO — see M9_PORT.md if/when one is confirmed), so this is
  // just poll + drain, no backlight tick.
  m9KeyboardPoll();
  for (int kbi = 0; kbi < 12; ++kbi) {
    int key = m9KeyboardReadKey();
    if (key <= 0) break;
    if (!_screen_off) s_kb_last_key_ms = now;
    if (s_remote_mode) { remotePhysicalKey(key); continue; }   // remote mode: physical keys are the exit
    handleHwKey(key);
  }
  serviceLockscreen();
  serviceLockingCountdown(now);
#endif
#if !defined(HAS_TANMATSU)
  // While a web-mirror browser is connected, count it as activity so the device screen
  // stays awake (otherwise the idle timer would dim it and swallow remote input).
  if (g_web_mirror.active()) {
    static uint32_t s_web_awake_ms = 0;
    if (now - s_web_awake_ms > 3000) { noteUserInput(); s_web_awake_ms = now; }
    // Tell the browser to summon/hide the phone soft keyboard when an editable field
    // gains/loses focus (the browser can't see the pixels to know).
    lv_obj_t* fta = g_lv.keyboard ? lv_keyboard_get_textarea(g_lv.keyboard) : nullptr;
    g_web_mirror.setKbFocused(fta != nullptr);
#if defined(HAS_TDECK_KEYBOARD) || defined(HAS_M9_KEYBOARD)
    // Physical-keyboard boards hide the on-screen keyboard, so browser keystrokes are
    // injected via the same path as the hardware keys (printable chars type in; 0x08 =
    // backspace, 0x0D = enter/send).
    uint16_t wk;
    for (int i = 0; i < 16 && g_web_mirror.popKey(&wk); ++i)
      handleHwKey((int)wk);
#else
    // On-screen-keyboard boards (V4/RAK): the browser's laptop keyboard should type too, not
    // only pointer-taps on the on-screen keys. Inject into the focused field — which IS the
    // keyboard's textarea (the mirror strip on these boards), so it behaves exactly like an
    // on-screen key tap and syncs to the real field on Enter. Enter fires the keyboard's
    // ready cb (send/next); backspace deletes; other printables type in.
    uint16_t wk;
    for (int i = 0; i < 16 && g_web_mirror.popKey(&wk); ++i) {
      if (!fta) continue;   // no editable field focused -> drain + drop
      if (wk == 0x0D || wk == 0x0A)      lv_event_send(g_lv.keyboard, LV_EVENT_READY, nullptr);
      else if (wk == 0x08 || wk == 0x7F) lv_textarea_del_char(fta);
      else if (wk >= 0x20)               lv_textarea_add_char(fta, (uint32_t)wk);
    }
#endif
  }
#endif
#if defined(HAS_TANMATSU)
  // Drive the keyboard backlight from off/on/auto + the Keys-slider brightness; keep it
  // dark whenever the screen is off/locked. The tick caches, so this per-frame call only
  // hits the CH32 over I2C when the value actually changes.
  tanKbBacklightTick(_screen_off || _manual_lock);
#endif
  refreshLiveDiag(now);
  // Keep the signal fresh with a "discover" probe: send a ZERO-HOP advert whenever
  // we have no recent DIRECT signal. Zero-hop = neighbours only, never re-broadcast,
  // so the probe injects NO repeated traffic into the mesh — it just announces us to
  // whoever is in direct range. The reading itself comes passively from directly-heard
  // (0-hop) neighbours (logRxRaw gates the signal to hops==0), so in a fully silent
  // mesh the icon stays dark until a neighbour transmits — the honest answer (no direct
  // neighbour = no direct signal). Off / poll-interval live in the "Signal & traffic" popup.
  {
    // s_sig_probe_at is file-scope (promoted for tsNextWakeForcingDueMs); no re-init here.
    (void)0;  // placeholder — variable declared at file scope above
    if ((long)(now - s_sig_probe_at) >= 0) {
      if (touchPrefsGetSigProbeEnabled()) {
        const uint32_t poll_ms = (uint32_t)touchPrefsGetSigPollMins() * 60000UL;  // minutes -> ms
        s_sig_probe_at = now + poll_ms;
        const uint32_t sms = the_mesh.uiSignalMs();
        // Skip the announce when a direct neighbour was heard within the poll window.
        if (sms == 0 || (now - sms) >= poll_ms - 5000UL) sendSignalProbe();
      } else {
        s_sig_probe_at = now + 60000;   // probe off: just re-check the toggle each minute
      }
    }
  }

  // Room-session self-heal (issue #89): while a room-server chat is OPEN, make sure
  // its login session is alive. The keep-alive only arms from a LOGIN_OK, so a
  // session from before this build — or one the core expired (2.5x the interval
  // with no ACK), or one the server dropped (reboot, LRU eviction, 3 failed
  // pushes) — needs a fresh login to resume both directions. A blank login is
  // enough for a client the room already knows (no password re-entry) and skips
  // the server's replay guard. Throttled to one attempt a minute, chat open only.
  {
    static uint32_t s_room_relogin_ms = 0;
    if (g_lv.dm.detail_open && g_lv.task && g_lv.task->hasActiveThread() &&
        !g_lv.task->activeThreadIsChannel() &&
        (uint32_t)(now - s_room_relogin_ms) >= 60000UL) {
      uint8_t rpub[32];
      if (g_lv.task->getThreadContactPub(g_lv.task->activeThreadIdx(), rpub) &&
          !the_mesh.uiHasConnectionTo(rpub)) {
        ContactInfo* rc = the_mesh.lookupContactByPubKey(rpub, PUB_KEY_SIZE);
        if (rc && rc->type == ADV_TYPE_ROOM) {
          s_room_relogin_ms = (uint32_t)now;
          the_mesh.uiRoomRelogin(rpub);   // LOGIN_OK re-arms the keep-alive + resyncs
        }
      }
    }
  }

  // Periodic self-advert: the standard MeshCore flood / zero-hop advert on a timer (intervals set
  // in the Advertise app, stored in TouchPrefsStore). Separate from the signal probe above, which
  // only floods when the mesh has gone quiet. First fire lands one full interval after enable/boot.
  {
    // One-shot flood self-advert shortly after boot (opt-in, #76; off by default). Refreshes our
    // pubkey for peers with auto-add on — useful after a reflash wiped storage and left them a stale
    // identity. Fires once per boot; enabling mid-session waits for the next boot (it IS a boot advert).
    static bool     s_boot_adv_done = false;
    static uint32_t s_boot_adv_at   = 0;
    if (!s_boot_adv_done) {
      if (!touchPrefsGetBootAdvert())      s_boot_adv_done = true;              // disabled — never fire this session
      else if (!s_boot_adv_at)             s_boot_adv_at   = (uint32_t)now + 6000u;   // arm ~6s after first loop
      else if ((int32_t)((uint32_t)now - s_boot_adv_at) >= 0) {
        the_mesh.sendAdvert(true);         // flood: reaches peers across repeaters (region-scoped like #68)
        s_boot_adv_done = true;
      }
    }

    static uint32_t s_next_flood_adv = 0, s_next_local_adv = 0;
    const uint16_t fh = touchPrefsGetFloodAdvHrs();
    if (fh) {
      if (!s_next_flood_adv) s_next_flood_adv = (uint32_t)now + (uint32_t)fh * 3600000UL;
      else if ((int32_t)((uint32_t)now - s_next_flood_adv) >= 0) {
        the_mesh.sendAdvert(true);   // flood: relayed across the mesh (region-scoped like #68)
        s_next_flood_adv = (uint32_t)now + (uint32_t)fh * 3600000UL;
      }
    } else s_next_flood_adv = 0;
    const uint16_t lm = touchPrefsGetLocalAdvMin();
    if (lm) {
      if (!s_next_local_adv) s_next_local_adv = (uint32_t)now + (uint32_t)lm * 60000UL;
      else if ((int32_t)((uint32_t)now - s_next_local_adv) >= 0) {
        the_mesh.sendAdvert(false);  // zero-hop: only neighbours hear it
        s_next_local_adv = (uint32_t)now + (uint32_t)lm * 60000UL;
      }
    } else s_next_local_adv = 0;
  }

  batteryLogTick((uint32_t)now);   // 5-min battery sample (SD on T-Deck, else SPIFFS)
#if CAP_SD
  telemetryPollTick((uint32_t)now); // auto-poll due nodes -> log (no window)
#endif
  uiCp("ui:verchk");
  versionCheckService(now);   // firmware update check (gear badge + About line)
  uiCp("ui:sbar");
  refreshSysInfo(now);        // live uptime / heap on the About sub-tab
#if defined(HAS_TDECK_GT911)
  refreshSleepDiag(now);     // live sleep counters on the Lock settings panel
#endif
  wifiScanService();          // draw Wi-Fi scan results when the worker finishes
  ctDeleteServiceTick();      // chunked contacts bulk-delete (advances the progress bar)

  // Accidental tab-switch guard: while content is actively being scrolled (and
  // for a short grace period after the scroll ends), make the bottom tab bar
  // ignore clicks so a stray finger landing on it mid-scroll can't change tabs.
  // Deliberate tab taps when not scrolling are unaffected.
  {
    static unsigned long s_tabbar_lock_until = 0;
    static bool s_tabbar_locked = false;
    lv_indev_t* indev = lv_indev_get_next(nullptr);
    if (indev && lv_indev_get_scroll_obj(indev) != nullptr) {
      s_tabbar_lock_until = now + 350;
    }
    // Also hard-lock the tab bar while Snake is open so a swipe/tap near the
    // bottom can't slip through to the app switcher (e.g. into the map).
    const bool want_lock = (now < s_tabbar_lock_until) || SnakeGame::isOpen();
    if (want_lock != s_tabbar_locked && g_lv.tabview) {
      lv_obj_t* tab_btns = lv_tabview_get_tab_btns(g_lv.tabview);
      if (tab_btns) {
        if (want_lock) lv_obj_clear_flag(tab_btns, LV_OBJ_FLAG_CLICKABLE);
        else           lv_obj_add_flag(tab_btns, LV_OBJ_FLAG_CLICKABLE);
        s_tabbar_locked = want_lock;
      }
    }
  }

  // microSD activity LED: lit for k_sd_io_led_ms after the last SD access
  // (markSdIo). Edge-triggered — LVGL is only touched when the lit/dark state
  // flips, so an idle device costs one comparison per loop and nothing else.
  if (g_statusbar.sd_icon) {
    static int8_t s_sd_led = -1;   // -1 = unset -> forces the initial sync
    const bool lit = (g_sd_io_ms != 0) &&
                     ((uint32_t)(now - g_sd_io_ms) < k_sd_io_led_ms);
    if ((int8_t)lit != s_sd_led) {
      s_sd_led = lit;
      if (lit) lv_obj_clear_flag(g_statusbar.sd_icon, LV_OBJ_FLAG_HIDDEN);
      else     lv_obj_add_flag(g_statusbar.sd_icon, LV_OBJ_FLAG_HIDDEN);
    }
  }

  // Async mesh-request spinner: blink the centre glyph while a request is sending
  // or awaiting a reply (recent markMeshRequest, a pending UI reply, or the LOS
  // worker). Cheap — a blink toggle, no animation.
  if (g_statusbar.async_icon) {
    const bool active = (g_mesh_req_ms != 0 && (uint32_t)(now - g_mesh_req_ms) < 1500u)
                        || (s_ui_ping_deadline_ms != 0)
                        || (s_telem_manual_pending && s_telem_deadline_ms != 0)  // manual telemetry req stays lit for its whole pending window, like a ping
                        || s_los_busy;
    static bool     s_async_shown = false;
    static uint32_t s_async_blink = 0;
    if (active) {
      if ((uint32_t)(now - s_async_blink) >= 350u) {
        s_async_blink = (uint32_t)now;
        s_async_shown = !s_async_shown;
        if (s_async_shown) lv_obj_clear_flag(g_statusbar.async_icon, LV_OBJ_FLAG_HIDDEN);
        else               lv_obj_add_flag(g_statusbar.async_icon, LV_OBJ_FLAG_HIDDEN);
      }
    } else if (!lv_obj_has_flag(g_statusbar.async_icon, LV_OBJ_FLAG_HIDDEN)) {
      s_async_shown = false;
      lv_obj_add_flag(g_statusbar.async_icon, LV_OBJ_FLAG_HIDDEN);
    }
  }

#if defined(HAS_TANMATSU)
  navMaybeRebuild();   // keep the keyboard-nav focus group in sync with the visible screen
  navPump();           // drain bsp keys: queue focus moves, type straight into focused fields
#elif defined(TLORA_PAGER)
  // No touch fallback here either (like Tanmatsu) -- nav is always on, just fed
  // from the keyboard/encoder drain above instead of a bsp queue.
  navMaybeRebuild();
#elif CAP_KEYPAD_NAV
  // Keep the focus group synced whenever EITHER nav mode is active: the keyboard ESDFX nav
  // (T-Deck) / d-pad nav (M9) fed by handleHwKey, or the trackball D-pad nav (fed by
  // updateTrackball -> navMoveDir).
  if (s_kbd_nav || s_tb_nav) navMaybeRebuild();
#endif
#if !defined(HAS_TANMATSU)
  // Web UI mirror: on a new connect / heal, invalidate the whole screen so LVGL
  // redraws it into the shadow buffer (takeFullRepaint is armed by the WS server).
  if (g_web_mirror.active() && g_web_mirror.takeFullRepaint())
    lv_obj_invalidate(lv_scr_act());
#endif
  uiCp("ui:lvgl");
  lv_timer_handler();
  uiCp("ui:tail");
#if !defined(HAS_TANMATSU)
  webMirrorTick();   // coalesced, rate-capped, backpressure-gated send of the dirty region
#endif
#if defined(HAS_TANMATSU)
  if (s_nav_entered_obj) {
    lv_obj_t* ent = s_nav_entered_obj; s_nav_entered_obj = nullptr;
    // WIZARD ONLY: after Enter on an option, jump to the primary action so the next Enter confirms.
    // In the main app this drifted focus to the last collected item (the Send-advert button), so it's
    // gated to the first-boot wizard (s_setup_root).
    if (s_setup_root && s_nav_group && lv_obj_is_valid(ent) && lv_group_get_focused(s_nav_group) == ent &&
        !lv_obj_check_type(ent, &lv_switch_class) && !lv_obj_check_type(ent, &lv_checkbox_class) &&
        s_nav_last && s_nav_last != ent && lv_obj_is_valid(s_nav_last))
      lv_group_focus_obj(s_nav_last);
  }
#endif
#if defined(HAS_TDECK_GT911)
  // Deferred microSD FAT32 format (runs a couple ticks after the notice paints).
  // f_mkfs blocks the loop for tens of seconds on a big card, so drop the loop
  // watchdog around it (CPU0 idle keeps running, so no reset) to avoid a
  // mid-format reset that would corrupt the card.
  if (s_sd_format_pending && --s_sd_format_pending == 0) {
    disableLoopWDT();
    SPIClass* spi = tdeckSharedSPI();
    bool ok = false;
    if (spi) {
      // Explicit reformat (not SD.begin's format_if_empty, which only formats an
      // already-unreadable card): init the card to register the FatFs diskio at
      // pdrv (no mount), f_mkfs to FAT32, write the MESHCOMOD label by hand while
      // unmounted, release, then remount the fresh FS via SD.begin. Works on any
      // card (FAT32, exFAT, blank) since f_mkfs hardware-inits + overwrites it.
      SD.end();                                          // drop any existing mount
      uint8_t pdrv = sdcard_init(PIN_SD_CS, spi, 4000000);
      if (pdrv != 0xFF) {
        char drv[3] = { (char)('0' + pdrv), ':', 0 };
        void* work = malloc(4096);                       // f_mkfs scratch (>= FF_MAX_SS)
        if (work) {
          if (f_mkfs(drv, MC_FM_FAT32, 0, work, 4096) == 0 /*FR_OK*/) {
            sdWriteFatLabel(pdrv, "MESHCOMOD");
            ok = true;
          }
          free(work);
        }
        sdcard_uninit(pdrv);
      }
      if (ok) ok = SD.begin(PIN_SD_CS, *spi, 4000000, "/sd", 3);
    }
    enableLoopWDT();
    fmHideFormatOverlay();
    if (ok && SD.cardType() != CARD_NONE) {
      s_sd_mounted = true;
      s_sd_size = SD.cardSize();
      sdEnsureMeshcomodFolders();                        // BINS / RECBCK / SETTINGS / MAPS / LOGS
      char done[56], cs[16];
      fmFmtSize64(s_sd_size, cs, sizeof cs);
      snprintf(done, sizeof done, TR("SD formatted - %s (MESHCOMOD)"), cs);
      showAlert(done, 3500);
    } else {
      s_sd_mounted = false;
      showAlert(TR("Format failed (no card / SD error)"), 3500);
    }
    if (s_fm_list) fmShowRoots();
  }
  // Deferred copy/move (paste). WDT off — a big tree can take a while.
  if (s_fm_paste_pending && --s_fm_paste_pending == 0) {
    disableLoopWDT();
    bool ok = fmDoPaste();
    enableLoopWDT();
    fmHideFormatOverlay();
    showAlert(ok ? TR("Pasted") : TR("Paste failed"), ok ? 1500 : 2400);
    if (s_fm_list) fmRefresh();
  }
#endif
#endif
}

void UITask::setBootPhase(const char* label) {
  (void)label;
}

void UITask::shutdown(bool restart) {
  (void)restart;
  // Flush chat history before we go down.
  if (_threads_dirty) saveThreadsToStorage();
  if (_msgs_dirty) saveMsgsToStorage();
#if defined(ESP32)
  touchPrefsSetClockFloor(rtc_clock.getFloor());   // clock floor: final synchronous save (#89)
#endif
  if (_display) {
    _display->startFrame();
    _display->drawTextCentered(_display->width() / 2, _display->height() / 2, "Shutting down...");
    _display->endFrame();
  }
}

// ============================================================================
// Unified popup registry — the ONE table behind anyPopupOpen(), the Esc/red-X
// dismiss ladder and the tab-swipe blocker (thin wrappers defined mid-file).
// Ordered topmost-first: the dismiss walker closes the FIRST open entry, so a
// row's position IS its z/priority. Lives at EOF so every popup's static root
// and closer is already declared. Adding a popup = adding ONE row here — it is
// then counted, Esc-dismissable and swipe-aware everywhere at once.
//   is_open : whether the popup is showing
//   close   : dismiss it (all closers route through popupClose()); nullptr =
//             not user-dismissable (progress overlays stay up until done)
//   flags   : PF_COUNT = counts for anyPopupOpen(); PF_SWIPE = blocks tab swipes
// ============================================================================
struct PopupEnt { bool (*is_open)(); void (*close)(); uint8_t flags; };
static constexpr uint8_t PF_COUNT = 1;
static constexpr uint8_t PF_SWIPE = 2;
#define P_OPEN(root) []{ return (root) != nullptr; }
